my $output_dir = $zip_file;  # Change this to your desired output directory

$output_dir=~s{\.zip}{}gsi;

# Make sure the output directory exists
unless (-d $output_dir) {
    make_path($output_dir) or die "Failed to create output directory: $!";
}

# Open the zip file
my $unzip = IO::Uncompress::Unzip->new($zip_file)
    or die "Cannot open $zip_file: $UnzipError\n";

# Extract each file
while ($unzip->nextStream()) {
    my $file_name = $unzip->getHeaderInfo()->{Name};
    my $output_file = "$output_dir/$file_name";

    # Create subdirectories if needed
    my $dir = dirname($output_file);
    unless (-d $dir) {
        make_path($dir) or die "Failed to create directory $dir: $!";
    }

    # Open the output file for writing
    open my $fh, '>', $output_file or die "Cannot open $output_file: $!\n";

    # Write the contents of the file
    my $buffer;
    while (($unzip->read($buffer)) > 0) {
        print $fh $buffer;
    }

    close $fh;
  
}

$unzip->close();
		



