while($Table_XML=~m{(<table\-wrap ([^\>]+)\>(.*?)<\/table\-wrap>)}gsi)
	{

	my $Table=$1;

	$Table=~s{<colgroup><\?attributepistart([^\?]+)\?\>}{<colgroup$1>}gsi;



	
	$Table=~s{<td align=\"([^\"]+)\"}{<td}gsi;

	$Table=~s{<th align=\"([^\"]+)\"}{<th}gsi;

	
	
	
	
	$Table=~s{<th><\?attributepistart([^\?]+)\?>}{<th$1>}gsi;

	$Table=~s{<td><\?attributepistart([^\?]+)\?>}{<td$1>}gsi;

	$Table=~s{<th ([^\>]+)\><\?attributepistart([^\?]+)\?>}{<th $1$2>}gsi;

	$Table=~s{<td><\?attributepistart([^\?]+)\?>}{<td$1>}gsi;

	$Table=~s{<td ([^\>]+)\><\?attributepistart([^\?]+)\?>}{<td $1$2>}gsi;

	

	
		my $table=$Table;

		
	
		my $line = $`;
		my $lnum = ($line =~ s/\n/\n/g)+1;
		my $cnum = length(substr($line,rindex($line,"\n"),length($line)))+1;


	#-- Table ID
	my $Table_ID=$1 if ($Table=~m{<table\-wrap id=\"([^\"]+)\"}si);

	#-- Col count
	#my $colgroup=$1 if ($Table=~m#<tr>(.*?)</tr>#si);
	my $Cols;

	
	
	if($Table=~m{<colgroup cols=\"([^\"]+)\"}gsi)
	{
		$Cols=$1;
	}


	
	my @rows=();
			
	my $title=$& if ($table=~m#<caption>.*?</caption>#gsi);

	$table=~s{<th }{<td }gsi;

	$table=~s{<\/th>}{<\/td>}gsi;

	my $Tables=$table;

	

	for(my $i=1;$i<=$Cols;$i++)
	{
		my @Row;

		$Tables=~s{<\?align (\w+)\?> <\?char ([^\?]+)\?>}{}gsi;

		$Tables=~s{<\?(\w+) (\w+)\?>}{}gsi;


		
		
		

		$Tables=~s{<\?attributepistart([^\>]+)\>}{}gsi;

		$Tables=~s{<td ([^\>]+)\>(<graphic ([^\>]+)\>)<\/td>}{<td $1><p>$2<\/p><\/td>}gsi;

		$Tables=~s{<p>(.*?)<\/p>}{$1}gsi;

		$Tables=~s{ rowspan=\"([^\"]+)\"}{}gsi;

		$Tables=~s{ colspan=\"([^\"]+)\"}{}gsi;
		
				
		while($Tables=~m{<td colname=\"col$i\"([^\>]*)\>(.*?)<\/td>}gsi)
		{
			
			push(@Row,$2);
		}

		my $Final_Row=join("",@Row);

		
		
		if($Final_Row!~m{\w}gsi)
		{
			
			
			
			open (ERR, ">>$ERR_File") || die "Can't create XML file '$ERR_File': $!\n\n\n";
			{
 
       
				print ERR "Warning at line 0 : Dummy column present in Column $i of Table $Table_Count .\n\n\n";
    
			}
			 

			 close(ERR);
		}


		my $Tab=$Tables;

		$Tab=~s{<td colname=\"col$i\" colspan=\"([^\"]+)\">}{}gsi;

		if($Tab!~m{<td colname=\"col$i\"}gsi)
		{
			open (ERR, ">>$ERR_File") || die "Can't create XML file '$ERR_File': $!\n\n\n";
			{
 
       
				print ERR "ERROR at line 0 :Column $i is fully spanned in the table $Table_Count.\n\n\n";
    
			}
			 

			 close(ERR);
		}
	}

	$table=~s{<th }{<td }gsi;

	$table=~s{<\/th>}{<\/td>}gsi;

	
	$table=~s{<th><\?attributepistart([^\>]?)\>}{<th $1>}gsi;

	$table=~s{<td><\?attributepistart([^\>]?)\>}{<td $1>}gsi;

	$table=~s{<th><\?attributepistart([^\?]+)\?>}{<th$1>}gsi;

		$table=~s{<td><\?attributepistart([^\?]+)\?>}{<td$1>}gsi;

		$table=~s{<th ([^\>]+)\><\?attributepistart([^\?]+)\?>}{<th $1$2>}gsi;

		$table=~s{<td><\?attributepistart([^\?]+)\?>}{<td$1>}gsi;

		$table=~s{<td ([^\>]+)\><\?attributepistart([^\?]+)\?>}{<td $1$2>}gsi;

		$table=~s{<\?attributepistart([^\>]+)\>}{}gsi;

		

	
	
	#-- Empty colspan expansion
	$table=~s#(<td [^\>]*?colspan="(\d+)"[^\>]*?>.*?</td>)#"$1".&CreateEmptyCol($2, $&)#gesi;

	
	sub CreateEmptyCol
	{
			my $num=shift;
			my $tag=shift;
			my $empty='';
			for (my $i=1; $i<$num; $i++)
			{
				$empty.="<td type=\"emptycol\"></td>\n";
			}
			return $empty;
	}
	
	#-- Empty rowspan expansion
	while ($table=~m#<tr[^\>]*?>(.*?)</tr>#gsi)
	{
			my $row=$1;
			$row=~s#\n##gsi;
			$row=~s#</td><td#</td>\n<td#gsi;
			my @entArr=split("\n",$row);
			push(@rows,\@entArr);
			
	}

	
	
	for (my $i=0; $i<=$#rows; $i++)
	{
			my $cnt=@{ $rows[$i] };
			for (my $j=0; $j<=$cnt; $j++)
			{
					my $cur_rowCol=$rows[$i][$j];
					if ($cur_rowCol=~m#rowspan=\"(\d+)\"#si)
					{
							my $spannum=$1-1;
							for (my $k=1; $k<=$spannum; $k++)
							{
								my $colspannum=$1-1 if ($cur_rowCol=~m#colspan=\"(\d+)\"#si);
								my $emprow='';
								for (my $l=1; $l<=$colspannum; $l++)
								{
									$emprow.="<td type=\"emptyrow\"></td>\n";
								}
								
								my $next_rowCol=$emprow."<td type=\"emptyrow\"></td>\n".$rows[$i+$k][$j];
								$rows[$i+$k][$j]=$next_rowCol;
							}
					}
			}
	}  



	
	#-- Create New Table from Two Dimentional Array
	my @NewTable=();
	for (my $i=0; $i<=$#rows; $i++)
	{  
			push (@NewTable,"<tr>");
			my $cnt=@{ $rows[$i] };
			for (my $j=0; $j<=$cnt; $j++)
			{
					push (@NewTable,$rows[$i][$j]);
			}
			push (@NewTable,"</tr>");
	}  
	my $newtable=join("",@NewTable);
	$newtable=~s#\n##gsi;
	$newtable=~s#</tr><tr#</tr>\n<tr#gsi;

	
	
	my @tablVal=split("\n",$newtable);
	
	for (my $i=0; $i<=$#tablVal; $i++)
	{
			my $entry=$tablVal[$i];
			my $entryCols=$entry=~s#<td#<td#gsi;

			
			
			if ($entryCols ne $Cols)
			{

				open (ERR, ">>$ERR_File") || die "Can't create XML file '$ERR_File': $!";
				{
 
       
				print ERR "Warning at line 0 :Check the columns count in table $Table_Count of row $i\n\n";
    
				}
			 	close(ERR);

				
				
				
			}
	}
	

	$Table_Count++;
	}

		
