sub Affiliation
{
	my $Aff=shift;

	my $Publisher_Name=shift;

	my $Publisher_Name1=$Publisher_Name;

	

	if($Publisher_Name1=~m{(Public Library of Science)}gsi)
	{
	
	$Aff=~s{<affxrefonline>(.*?)<\/affxrefonline>}{<affxref>$1<\/affxref>}gsi;

	}


	
	
	
	$Aff=~s{<\/italic>(\s?)<sup>(\d+)<\/sup>(\s?)<italic>(.*?)<\/italic>}{<\/italic><\/aff>\n<aff><sup>$2<\/sup>$3<italic>$4<\/italic><\/aff>}gsi;

	if($Tmp=~m{<publisher>\n<publisher-name>OUP</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Oxford University Press</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Public Library of Science</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Adi Health\+Wellness</publisher-name>}si)
	{

		$Aff=~s{<italic>}{}gsi;
		$Aff=~s{<\/italic>}{}gsi;
		

	$Aff=~s{<affxref>}{<affxref1>}si;
	
	$Aff=~s{<affxref>(\s)}{ <affxref>}gsi;
		
	$Aff=~s{(\s?)<affxref>}{$1<\/aff>\n<aff><affxref>}gsi;

	$Aff=~s{<affxref1>}{<affxref>}si;	

	$Aff=~s{<\/fmaff([^\>]+)\><affxref>}{<\/fmaff$1\><\/aff>\n<aff><affxref>}gsi;

