	$key=~s{<\/kwd>\<kwd>}{<\/kwd><x>$1<\/x><kwd>}gsi;

	
	$key=~s{(<\/kwd>)([\.\,\;]?)(\s?)(\<CommentReference\d+/>)(.*?)(\<kwd>)}{$1<x>$2$3$4$5<\/x>$5}gsi;

	
	
	$key=~s{(<\/kwd>)([\.\,\;]?)(\s?)(<query>(.*?)<\/query>)(.*?)(\<kwd>)}{$1<x>$2$3$4$6<\/x>$7}gsi;

	$key=~s{(<\/kwd>)([\.\,\;\s]?)(\&\#(\w+)\;)(\s?)(<query>(.*?)<\/query>)(.*?)(\<kwd>)}{$1<x>$2$3$5$6$8<\/x>$9}gsi;

	$key=~s{(<\/kwd>)([\.\,\;]?)(\s?)(\<CommentReference/>)(.*?)(\<kwd>)}{$1<x>$2$3$4$5<\/x>$6}gsi;

	$key=~s{(<\/kwd>)([\.\,\;]?)(\s?)(<query>(.*?)<\/query>)$}{$1<x>$2$3$4<\/x>}gsi;

	
	
	$key=~s{(<\/kwd>)([\.\,\;\s]?)(\&\#(\w+)\;)(\s?)(<query>(.*?)<\/query>)$}{$1<x>$2$3$4$5<\/x>}gsi;

	#$key=~s{<\/title>(\s)}{<\/title>}gsi;

	
	
	
	
	if($key!~m{<kwd>}si)
	{
		if($key=~m{<query>(.*?)<\/query>}si)
		{
			$key=~s{<query>(.*?)<\/query>}{<kwd><query>$1<\/query><\/kwd>}gsi;
		}
	}

	$key=~s{(\s?)\.$}{<x>$1\.<\/x>}gsi;

	$key=~s{(\s?)\,$}{<x>$1\,<\/x>}gsi;


	


	$key=~s{\[\[\[ins\]\]\](\s?)([\.\;\:]+)\[\[\[\/ins\]\]\]([^\n]*)$}{<x>\[\[\[ins\]\]\]$1$2\[\[\[\/ins\]\]\]$3<\/x>}gsi;

	$key=~s{\[\[\[del\]\]\](\s?)([\.\;\:]+)\[\[\[\/del\]\]\]([^\n]*)$}{<x>\[\[\[del\]\]\]$1$2\[\[\[\/del\]\]\]$3<\/x>}gsi;

	$key=~s{\[\[\[del\]\]\](\s?)([\.\;\:]+)\[\[\[\/del\]\]\]$}{<x>\[\[\[del\]\]\]$1$2\[\[\[\/del\]\]\]<\/x>}gsi;

	$key=~s{\[\[\[ins\]\]\](\s?)([\.\;\:]+)\[\[\[\/ins\]\]\]$}{<x>\[\[\[ins\]\]\]$1$2\[\[\[\/ins\]\]\]<\/x>}gsi;

	$key=~s{\[\[\[ins\]\]\](\s?)\[\[\[\/ins\]\]\]$}{<x>\[\[\[ins\]\]\]$1$2\[\[\[\/ins\]\]\]<\/x>}gsi;

	
	if($Tmp=~m{<publisher>\n<publisher-name>OUP</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Oxford University Press</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Lippincott Williams \&\#x0026; Wilkins</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Public Library of Science</publisher-name>}si || $Tmp=~m{<publisher>\n<publisher-name>Adi Health\+Wellness</publisher-name>}si)
{

	
	my $Count_B=$key=~s{\[\[\[del\]\]\]}{\[\[\[del\]\]\]}gsi;
	if($Count_B eq 1)
	{
		
		$key=~s{^(\n?)(\[\[\[del\]\]\](.*?)\[\[\[\/del\]\]\])$}{<x>$2<\/x>}gsi;

		
		
		
	}

	
	

}

	

	
	$key=~s{<\/title>(\s)<kwd>}{<\/title><x>$1<\/x><kwd>}gsi;
			
	$key=~s{<sc><kwd>}{<kwd><sc>}gsi;

	$key=~s{</kwd></sc>}{</sc></kwd>}gsi;

	$key=~s{ <\/kwd><x>}{<\/kwd><x> }gsi;
	
	
	return $key;	  

}

sub Bib_xref
{
	my $Xref=shift;

	

	
	$Xref=~s{<sup>}{}gsi;
	$Xref=~s{<\/sup>}{}gsi;

	
	
	if($Xref=~m{^(\d+)\,}gsi)
	{
		$Xref=~s{^(.*?)$}{&Xref_Comma($1)}gesi;
	}
	elsif($Xref=~m{^\((\d+)\,}gsi)
	{
		$Xref=~s{^\((.*?)$}{"\(".&Xref_Comma($1)}gesi;
	}
	elsif($Xref=~m{^\[(\d+)\,}gsi)
	{
		$Xref=~s{^\[(.*?)$}{"\[".&Xref_Comma($1)}gesi;
	}
	elsif($Xref=~m{^(\d+)\&ndash;(\d+)}gsi)
	{
		$Xref=~s{^(\d+)\&ndash;(\d+)}{&xref($1,$2)}gesi;
	}
	
	elsif($Xref=~m{^(\d+)\-(\d+)}gsi)
	{
		$Xref=~s{^(\d+)\-(\d+)}{&xref_hyphen($1,$2)}gesi;
	}
	elsif($Xref=~m{^\[(\d+)\-(\d+)}gsi)
	{
		$Xref=~s{^\[(\d+)\-(\d+)}{"\[".&xref_hyphen($1,$2)}gesi;
	}
	elsif($Xref=~m{^\((\d+)\-(\d+)}gsi)
	{
		$Xref=~s{^\((\d+)\-(\d+)}{"\(".&xref_hyphen($1,$2)}gesi;
	}
	elsif($Xref=~m{^\((\d+)\&ndash;(\d+)}gsi)
	{
		$Xref=~s{^\((\d+)\&ndash;(\d+)}{"\(".&xref($1,$2)}gesi;
	}
	elsif($Xref=~m{^\((\d+)\-(\d+)}gsi)
	{
		$Xref=~s{^\((\d+)\-(\d+)}{"\(".&xref_hypen($1,$2)}gesi;
	}
	elsif($Xref=~m{^\[(\d+)\&ndash;(\d+)}gsi)
	{
		$Xref=~s{^\[(\d+)\&ndash;(\d+)}{"\[".&xref($1,$2)}gesi;
	}
	elsif($Xref=~m{^\[(\d+)\-(\d+)}gsi)
	{
		$Xref=~s{^\[(\d+)\-(\d+)}{"\[".&xref_hyphen($1,$2)}gesi;
	}
	elsif($Xref=~m{(\d+)\-(\d+)}gsi)
	{
		$Xref=~s{(\d+)\-(\d+)}{&xref_hyphen($1,$2)}gesi;
	}

	if($Xref=~m{^(\d+)$}gsi)
	{
		$Xref=~s{^(.*?)$}{&Xref_Comma($1)}gesi;
	}
	if($Xref=~m{^\((\d+)\)$}gsi)
	{
		$Xref=~s{^\((.*?)\)$}{"\(".&Xref_Comma($1)."\)"}gesi;
	}
	if($Xref=~m{^\[(\d+)\]$}gsi)
	{
		
		
		$Xref=~s{^\[(.*?)\]$}{"\[".&Xref_Comma($1)."\]"}gesi;
		
	}
	if($Xref=~m{(\d+)\&ndash;(\d+)}gsi)
	{
		
		$Xref=~s{(\d+)\&ndash;(\d+)}{&xref($1,$2)}gesi;
	}
	

	
	if($Xref=~m{<\/xref>(\,?)(\d+)(.*?)(\)?)(\]?)}gsi)
	{
		
		
		$Xref=~s{<\/xref>(\,?)(\d+)(.*?)(\)?)(\]?)}{"<\/xref>$1".&Xref_Comma($2.$3)."$4$5"}gesi;
		
	}
	

	
	
	$Xref=~s{^(.*?)$}{<sup>$1<\/sup>}gsi;
	
	return $Xref;
}

sub Bib_xref_sup
{
	my $Xref=shift;


	
	
	if($Xref=~m{^(\d+)\,}gsi)
	{
