		$table=~s{ colstubs=\"([^\"]+)\"\/>}{ colstubs=\"$1\">}gsi;

		$table=~s{colstubs=\"([^\"]+)\"}{"colstubs=\"".&Colstubs($1)."\""}gesi;

		my $table1=$table;
		
		my $Table_Col=$table;

		my $Publisher_Name2=$Publisher_Name;

		
		
		if($table1!~m{(single|Double|landscape)\/>}gsi)
		{
			

			
		if($Table_Col=~m{colstubs=\"([^\"]+)\"}gsi)
		{
			my $Colstubs=$1;

			

			if($Colstubs <=0.55)
			{
				$table=~s{<oasis\:entry([^\>]+)\>}{<oasis\:entry$1\><\?single single\?>}si;
			}
			elsif($Colstubs >=0.56 && $Colstubs <=1.04)
			{
				$table=~s{<oasis\:entry([^\>]+)\>}{<oasis\:entry$1\><\?double double\?>}si;
			}
			else
			{
				$table=~s{<oasis\:entry([^\>]+)\>}{<oasis\:entry$1\><\?landscape landscape\?>}si;
			}
			
		}
		}
		
		

		
	}

	if($Publisher_Name eq "Lippincott Williams \&\#x0026; Wilkins") 
	{
		

		$table=~s{<oasis\:entry([^\>]+)\><\/oasis\:entry>}{<oasis\:entry$1\> <\/oasis\:entry>}gsi;

	}

	$table=~s{(<oasis\:colspec ([^\>]+)\>\n*)(<oasis\:row>(.*?)<\/oasis\:row>\n<\/oasis:thead>)}{$1<oasis\:thead>\n$3}gsi;
	
	#$table=~s{<TabFnXref>(.*?)<\/TabFnXref>}{<sup>$1<\/sup>}gsi;

	
	#$table=~s{<oasis\:tgroup cols=\"([^\"]+)\"\/>}{<oasis\:tgroup cols=\"([^\"]+)\">}gsi;

	
	
	$table=~s{<\? PAGE \# \"\'Page\: \'\#\'\' TableAlignment}{<\?TableAlignment}gsi;

	$table=~s{\n}{<\?pi break1\?>}gsi;

	$table=~s{<tbody >}{<tbody>}gsi;
	
	return $table;

	
}

sub Thead
{
	my $Thead=shift;

	$Thead=~s{<oasis\:row>}{<oasis\:row rowsep=\"1\">}gsi;
	
