sub Person_Group
{
	my $Person=shift;

	
	
	my @Person_Data=split(',',$Person);
	my @Person_Split;

	
	foreach my $Per(@Person_Data)
	{
		
	$Per="<name>$Per<\/name>";
	push(@Person_Split,$Per);
	}
	
	my $Final_Person=join(',',@Person_Split);

	return $Final_Person;
}

sub Figure_Link
{
	my $Figure=shift;
	my $Fig_Id=shift;
	my $Fig_Let=shift;

	
		
if($Tmp=~m{<fig id=\"F($Fig_Id)($Fig_Let)\"}gsi)
{

	my $Fig=$1;
	my $Let=$2;
	
	$Figure=~s{(Fig(\w*)(\.?)(\s?)($Fig)(\.?)(\(?)($Let)(\)?))}{<xref ref-type=\"fig\" rid=\"F$5$8\">$1<\/xref>}si;
	
	
}
else
{
	
	$Figure=~s{(Fig(\w*)(\.?)(\s?)($Fig_Id)(\.?)(\(?)($Fig_Let)(\)?))}{<xref ref-type=\"fig\" rid=\"F$5\">$1<\/xref>}gsi;
}

return $Figure;

}

