	$Contrib=~s{<fmaucollab>(.*?)<\/fmaucollab>}{<contrib contrib-type=\"author\" corresp=\"no\"><collab>$1<\/collab></contrib>}gsi;

	$Contrib=~s{<contrib contrib-type="author" corresp="no"><collab>}{<contrib contrib-type="other" corresp="no"><collab>}gsi;

	
	
	

	my $C='1';
	my $C1='1';

	my $S='1';
	my $S1='1';

	my $G='1';
	my $G1='1';

	my @Fm_Authors;

	my $A='1';


	
	
	$Final_Authors=~s{<sc>(<\w([^\>]+)\>)}{$1<sc>}gsi;
	$Final_Authors=~s{<sc> (<\w([^\>]+)\>)}{ $1<sc>}gsi;

	$Final_Authors=~s{(<\/\w([^\>]+)\>)<\/sc>}{<\/sc>$1}gsi;
	$Final_Authors=~s{(<\/\w([^\>]+)\>)<\/sc>}{<\/sc>$1}gsi;

	
	#[[[del]]]PhD[[[/del]]]<fmauDegree>
	$Final_Authors=~s{\[\[\[del\]\]\]([^\[]+)\[\[\[\/del\]\]\]<fmaudegree>}{<fmaudegree>\[\[\[del\]\]\]$1\[\[\[\/del\]\]\]}gsi;

	
	
	#$Final_Authors=~s{<\/fmaudegree>([^\<]+)\<fmaudegree>}{$1}gsi;

	

	$Final_Authors=~s{<fmcorrSurname>([^\<]+)\</fmcorrSurname><fmcorrSurname><sc>}{<fmcorrSurname>$1<sc>}gsi;
	$Final_Authors=~s{<fmauSurname>([^\<]+)\</fmauSurname><fmauSurname><sc>}{<fmauSurname>$1<sc>}gsi;
	$Final_Authors=~s{<fmcorrGivenName>([^\<]+)\</fmcorrGivenName><fmcorrGivenName><sc>}{<fmcorrGivenName>$1<sc>}gsi;
	$Final_Authors=~s{<fmauGivenName>([^\<]+)\</fmauGivenName><fmauGivenName><sc>}{<fmauGivenName>$1<sc>}gsi;
	$Final_Authors=~s{<fmcorrGivenName><sc>([^\<]+)\<\/fmcorrGivenName>}{<GivenName><sc>$1</sc><\/GivenName>}gsi;
	$Final_Authors=~s{<fmcorrGivenName>([^\<]+)\<\/sc><\/fmcorrGivenName>}{<GivenName><sc>$1</sc><\/GivenName>}gsi;

	
	$Final_Authors=~s{<fmcorrSurName><sc>([^\<]+)\<\/fmcorrSurName>}{<SurName><sc>$1</sc><\/SurName>}gsi;
	$Final_Authors=~s{<fmcorrSurName>([^\<]+)\<\/sc><\/fmcorrSurName>}{<SurName><sc>$1</sc><\/SurName>}gsi;

	$Final_Authors=~s{<fmauGivenName><sc>([^\<]+)\<\/fmauGivenName>}{<GivenName><sc>$1</sc><\/GivenName>}gsi;
	$Final_Authors=~s{<fmauGivenName>([^\<]+)\<\/sc><\/fmauGivenName>}{<GivenName><sc>$1</sc><\/GivenName>}gsi;

	$Final_Authors=~s{<fmauSurName><sc>([^\<]+)\<\/fmauSurName>}{<SurName><sc>$1</sc><\/SurName>}gsi;
	$Final_Authors=~s{<fmauSurName>([^\<]+)\<\/sc><\/fmauSurName>}{<SurName><sc>$1</sc><\/SurName>}gsi;


	

	$Final_Authors=~s{</fmcorrDegree>\[\[\[ins\]\]\](.*?)\[\[\[\/ins\]\]\]<fmcorrDegree>}{$2}gsi;

	
	
	$Final_Authors=~s{</fmauDegree>\[\[\[ins\]\]\](.*?)\[\[\[\/ins\]\]\]<fmauDegree>}{$2}gsi;

	$Final_Authors=~s{</fmcorrDegree>\[\[\[del\]\]\](.*?)\[\[\[\/del\]\]\]<fmcorrDegree>}{}gsi;

	
	
	$Final_Authors=~s{</fmauDegree>\[\[\[del\]\]\](.*?)\[\[\[\/del\]\]\]<fmauDegree>}{}gsi;

	$Final_Authors=~s{</fmauDegree>\.}{\.</fmauDegree>}gsi;
	$Final_Authors=~s{</fmcorrDegree>\.}{\.</fmcorrDegree>}gsi;
	
	$Final_Authors=~s{<\/fm(\w+)Degree>(\s?)(\.?)(\,?)(\s?)<fm(\w+)Degree>}{$2$3$4$5}gsi;

	$Final_Authors=~s{<fmauDegree>(\s?)([\.\,\;\:]?)(\s?)<\/fmauDegree>}{$1$2$3}gsi;

	$Final_Authors=~s{<fmcorrDegree>([^\<]+)\<\/fmauDegree>}{<fmcorrDegree>$1<\/fmcorrDegree>}gsi;

	$Final_Authors=~s{<fmauDegree>([^\<]+)\<\/fmcorrDegree>}{<fmauDegree>$1<\/fmauDegree>}gsi;

	
	
	$Final_Authors=~s{<fm(\w+)degree>(.*?)<\/fm(\w+)degree>}{"<".$C++."><fm$1degree>$2<\/fm$1degree>"}egsi;

	$Final_Authors=~s{<surname>([^\<]+)\<\/surname>}{"<".$S++."><Surname>$1<\/Surname>"}egsi;

	$Final_Authors=~s{<GivenName>([^\<]+)\<\/GivenName>}{"<".$G++."><GivenName>$1<\/GivenName>"}egsi;

	
	
	
	#$Contrib=~s{<degrees>([^\<]+)\<\/degrees>}{"<".$C1++."><degrees>$1<\/degrees>"}egsi;


	if($Tmp=~m{<publisher>\n<publisher-name>Lippincott Williams \&\#x0026; Wilkins</publisher-name>}si)
	{

	
	while($Final_Authors=~m{<(\d+)><fm(\w+)degree>([^\<]+)\<\/fm(\w+)degree>}gsi)
	{
		
		my $Digit=$1;
		my $Content=$3;

		

		
		$Content=~s{<italic>}{}gsi;
		$Content=~s{<\/italic>}{}gsi;
		$Content=~s{<bold>}{}gsi;
		$Content=~s{<\/bold>}{}gsi;

		$Content=~s{<sc>([^\<]+)\<\/sc>}{\U$1}gsi;
		$Content=~s{<\/SC>}{<\/sc>}gsi;

		

		#$Contrib=~s{<$Digit><degrees>([^\<]+)\<\/degrees>}{<degrees>$Content<\/degrees>}gsi;
	}

	
	
	
	

		if($Journal_Cats eq "MAT")
		{
			
			#$Contrib=~s{ and }{ <sc>and<\/sc> }gsi;
			#$Contrib=~s{ <\/x>and }{ <sc>and<\/sc> <\/x>}gsi;
			##$Contrib=~s{<surname>(.*?)<\/surname>}{"<surname>".&Mat_Surname($1)."<\/surname>"}gesi;
			##$Contrib=~s{<given\-names>(.*?)<\/given\-names>}{"<given\-names>".&Mat_Surname($1)."<\/given\-names>"}gesi;

			##$Contrib=~s{\&\#<sc>x</sc>(\w+);}{<sc>\&\#x$1;<\/sc>}gsi;

			##$Contrib=~s{<\/sc><sc>}{}gsi;
		}


		
		
	}

	
	
	$Contrib=~s{<(\d+)>}{}gsi;
	$Contrib=~s{<affxref>(.*?)<\/affxref>}{}gsi;

	
	
	if($Contrib=~m{(<name>|<aff>)}si)
	{
	$Contrib=~s{<contrib>\n*<bio>}{<bio>}gsi;

	$Contrib=~s{<\/bio>\n*<\/contrib>}{<\/bio>}gsi;
	
	}

	
	
	$Contrib=~s{(By )(<contrib ([^\>]+)\><name>)}{$2<x>$1<\/x>}gsi;


	
	
	
	$Contrib=~s{<contrib contrib\-type=\"author non-byline\" corresp=\"no\"><contrib contrib\-type=\"author\" corresp=\"no\">}{<contrib contrib\-type=\"author non-byline\" corresp=\"no\">}gsi;


	
	
	$Contrib=~s{<\/contrib><\/contrib>}{<\/contrib>}gsi;

	$Contrib=~s{<\/contribs><\/contrib>}{<\/contrib>}gsi;

	
	
	
		
	$Contrib=~s{<sup>(\s?)\,(\s?)<\/sup>}{$1\,$2}gsi;

	$Contrib=~s{<cont contrib\-type=\"author non\-byline\" corresp="no"><contrib contrib-type="author" corresp=\"yes\">}{<contrib contrib-type="author non\-byline" corresp=\"yes\">}gsi;

	$Contrib=~s{<cont contrib\-type=\"author non\-byline\" corresp="no"><contrib contrib-type="author" corresp=\"no\">}{<contrib contrib-type="author non\-byline" corresp=\"no\">}gsi;


	
	
	$Contrib=~s{<contrib contrib\-type=\"author non\-byline\"><query>([^\<]+)\</query></contrib>}{<x><query>$1</query><\/x>}gsi;

	
	
	$Contrib=~s{<\/contribs><contrib contrib\-type=\"author non\-byline\" corresp=\"no\"><query>([^\<]+)\</query></contrib>}{<x><query>$1</query><\/x><\/contribs>}gsi;


	$Contrib=~s{<cont contrib\-type=\"author group\" corresp="no"><contrib contrib-type="author" corresp=\"yes\">}{<contrib contrib-type="author group" corresp=\"yes\">}gsi;

	$Contrib=~s{<cont contrib\-type=\"author group\" corresp="no"><contrib contrib-type="author" corresp=\"no\">}{<contrib contrib-type="author group" corresp=\"no\">}gsi;


	
	
	$Contrib=~s{<contrib contrib\-type=\"author group\"><query>([^\<]+)\</query></contrib>}{<x><query>$1</query><\/x>}gsi;

	
	
	$Contrib=~s{<\/contribs><contrib contrib\-type=\"author group\" corresp=\"no\"><query>([^\<]+)\</query></contrib>}{<x><query>$1</query><\/x><\/contribs>}gsi;




	
	

	

	#if(scalar(@Comment) ne "")
	#{
		
		#$Contrib=$Contrib." ".$Final_Contrib;
		
	#}
		
	#$Contrib=~s{<\/name><xref([^\>]+)\>(.*?)<\/xref><\/contribs><degrees>(.*?)<\/degrees>}{<\/name><degrees>$3<\/degrees><xref$1>$2<\/xref><\/contribs>}gsi;

	
	
	$Contrib=~s{<cont contrib\-type=\"author non\-byline\" corresp=\"([^\"]+)\"><given-names>([^\<]+)\</given-names></name></contrib><contrib contrib\-type=\"author non-byline\" corresp=\"([^\"]+)\"><name><given-names>([^\<]+)\</given-names>}{<contrib contrib-type="author non-byline" corresp=\"$1\"><name><given-names>$2$4</given-names>}gsi;

	$Contrib=~s{<cont contrib\-type=\"author non\-byline\" corresp=\"([^\"]+)\"><given-names>([^\<]+)\</given-names></name></contrib><contrib contrib\-type=\"author non-byline\" corresp=\"([^\"]+)\"><name><given-names>([^\<]+)\</given-names>}{<contrib contrib-type="author non-byline" corresp=\"$1\"><name><given-names>$2$4</given-names>}gsi;

	$Contrib=~s{<cont contrib\-type=\"author non\-byline\" corresp=\"([^\"]+)\"><given-names>([^\<]+)\</given-names></name></contrib><contrib contrib\-type=\"author non-byline\" corresp=\"([^\"]+)\"><name><surname>([^\<]+)\</surname><x>([^\<]+)\<\/x><contrib}{<contrib contrib-type="author non-byline" corresp=\"$1\"><name><given-names>$2</given-names>}gsi;


	$Contrib=~s{<given\-names></given\-names>}{}gsi;

	
	
	$Contrib=~s{<x>(\s?)\,(\s?)</x><OrcXref>([^\<]+)\<\/OrcXref>}{<OrcXref>$3<\/OrcXref>}gsi;

	
	
	
	return $Contrib;
}


sub contribauthor
{
	my $author=shift;
	

	
	
	
	
	
	if($Publisher_Name eq "IOP Publishing") 
	{
		

		
	
	$author=~s{<xref ref\-type=\"fn\" rid=\"([^\"]+)\"><sup>(\d+)<\/sup><\/xref>}{<fnxref>$2<\/fnxref>}gsi;

	}

	my $Sup=$author;
	
	
	$author=~s{<AffXrefonline>}{<affxref>}gsi;
	$author=~s{<fnxref>}{<affxref>}gsi;
	$author=~s{<\/fnxref>}{<\/affxref>}gsi;
	$author=~s{<fnxref1>}{<affxref>}gsi;
	$author=~s{<\/fnxref1>}{<\/affxref>}gsi;
	$author=~s{<fnxrefonline>}{<affxref>}gsi;
	$author=~s{<\/fnxrefonline>}{<\/affxref>}gsi;
	$author=~s{<fnxrefonline1>}{<affxref>}gsi;
	$author=~s{<\/fnxrefonline1>}{<\/affxref>}gsi;
	$author=~s{<\/AffXrefonline>}{<\/affxref>}gsi;
	$author=~s{</affXref><affXref>}{}gsi;
	$author=~s{</affXref>(\s?)\,(\s?)<affXref>}{$1\,$2}gsi;
	
	
	
	my $Xref;
	my $Original;

	my @Aff;


	
	
	
	
	if($author=~m{<affxref>(.*?)<\/affxref>}si)
	{
		$Xref=$1;

		
		
		$Original=$1;

		
		
		$Xref=~s{\[\[\[ins\]\]\]}{}gsi;
		$Xref=~s{\[\[\[\/ins\]\]\]}{}gsi;
		$Xref=~s{\[\[\[del\]\]\]}{}gsi;
		$Xref=~s{\[\[\[\/del\]\]\]}{}gsi;

	#$Xref=~s{<AffXrefonline>\[\[\[ins\]\]\]}{\[\[\[ins\]\]\]<AffXrefonline>}gsi;
