	#$Xref=~s{<AffXref>\[\[\[del\]\]\]}{\[\[\[del\]\]\]<AffXref>}gsi;

	#$Xref=~s{\[\[\[\/ins\]\]\]<\/AffXrefonline>}{<\/AffXrefonline>\[\[\[\/ins\]\]\]}gsi;
	#$Xref=~s{\[\[\[\/ins\]\]\]<\/AffXref>}{<\/AffXref>\[\[\[\/ins\]\]\]}gsi;
	#$Xref=~s{\[\[\[\/del\]\]\]<\/AffXrefonline>}{<\/AffXrefonline>\[\[\[\/del\]\]\]}gsi;
	#$Xref=~s{\[\[\[\/del\]\]\]<\/AffXref>}{<\/AffXref>\[\[\[\/del\]\]\]}gsi;

		
		#$Xref=~s{\,}{}gsi;

		
		$Xref=~s{\,}{iopcomma}gsi;
		
		$Xref=~s{(\d+)\&}{$1,\&}gsi;
		$Xref=~s{(\w+)\&}{$1,\&}gsi;
		$Xref=~s{\;\&}{\;,\&}gsi;
		$Xref=~s{\;(\d+)}{\;\,$1}gsi;
		$Xref=~s{\;(\|)}{\;\,$1}gsi;
		$Xref=~s{\,\,}{\,}gsi;

		#$Xref=~s{\&ast\;\,\&ast\;}{\&ast;\&ast;}gsi;

		$Xref=~s{\&(\w+);\,\&(\1);}{\&$1;\&$1;}gs;
		$Xref=~s{\&(\w+);\,\&(\1);}{\&$1;\&$1;}gs;

		

		$Xref=~s{iopcomma}{\,}gsi;

		$Xref=~s{\,\,}{\,}gsi;

		
		
		push(@Aff,$Xref);
		
	}

	my $Id=join(",",@Aff);


	
	
	my @Final_Id=split(",",$Id);

	
	

	my @Super;
	my @Link;


	
	
	
	foreach my $Value(@Final_Id)
	{
		
		my $Aff=0;

		
		
		if($Tmp=~m{<aff id=\"([^\"]+)\">(<sup>$Value<\/sup>)}s)
		{
	
			
			
			push(@Link,$1);
			push(@Super,$2);

			$Aff=1;
			#$author=$author."<xref ref-type=\"aff\" rid=\"$1\"><sup>$Value<\/sup><\/xref>";
			
		}
		elsif($Tmp=~m{<aff id=\"([^\"]+)\">(<sup>\[\[\[ins\]\]\]$Value\[\[\[\/ins\]\]\]<\/sup>)}s)
		{
	
			
			
			push(@Link,$1);
			push(@Super,$2);

			$Aff=1;
			#$author=$author."<xref ref-type=\"aff\" rid=\"$1\"><sup>$Value<\/sup><\/xref>";
			
		}
		elsif($Tmp=~m{<aff id=\"([^\"]+)\">(<sup>\[\[\[del\]\]\]$Value\[\[\[\/del\]\]\]<\/sup>)}s)
		{
	
			
			
			push(@Link,$1);
			push(@Super,$2);

			$Aff=1;
			#$author=$author."<xref ref-type=\"aff\" rid=\"$1\"><sup>$Value<\/sup><\/xref>";
			
		}
		elsif($Tmp=~m{<aff id=\"([^\"]+)\">\[\[\[ins\]\]\]$Value\[\[\[\/ins\]\]\]}s)
		{
			
			push(@Link,$1);
			push(@Super,$Value);

			$Aff=1;
			#$author=$author."<xref ref-type=\"aff\" rid=\"$1\"><sup>$Value<\/sup><\/xref>";
			
		}
		elsif($Tmp=~m{<aff id=\"([^\"]+)\">$Value}gs)
		{
			
			push(@Link,$1);
			push(@Super,$Value);

			$Aff=1;
	
			#$author=$author."<xref ref-type=\"aff\" rid=\"$1\"><sup>$Value<\/sup><\/xref>";
			
		}
		elsif($Tmp=~m{<aff id=\"([^\"]+)\"><sup>$Value(\.)<\/sup>}gs)
		{
			
			push(@Link,$1);
			push(@Super,$Value);

			$Aff=1;
	
