sub Superscript
{
	my $super=shift;

	my @comma=split(',',$super);

	my @Arr_comma;

	foreach my $Value(@comma)
	{
		$Value="AF000$Value";
		push(@Arr_comma,$Value);
	}

	my $Final_Comma=join(' ',@Arr_comma);

	my $Final_Value="<xref ref-type=\"aff\" rid=\"$Final_Comma\"><sup>$super<\/sup>";
		
	return $Final_Value;
}

sub title
{
	my $title=shift;
	$title=~s{<bold>}{}gsi;
	$title=~s{<\/bold>}{}gsi;
	$title=~s{<bold\/>}{}gsi;
	$title=~s{<italic>}{}gsi;
	$title=~s{<\/italic>}{}gsi;
	$title=~s{<italic\/>}{}gsi;
	return $title;
}
sub reftype
{
	
	my $ref=shift;
	
	
	$ref=~s{amphyphen}{\-}gsi;

	
	
	
	if($ref=~m{<conf\-name>}gsi)
	{
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"conf\">}gsi;
		
	}
	
	elsif($ref=~m{<edition>} || $ref=~m{<publisher\-loc>} || $ref=~m{<publisher\-name>} || $ref=~m{<book\-title>}gsi)
	{
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"book\">}gsi;
		
	}
	
	elsif($ref=~m{<uri xlink:href=\"(http|www)}gsi)
	{
		
		#$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"webpage\">}gsi;
		
	}
	elsif($ref=~m{<thesis\-title>}gsi)
	{
		
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"thesis\">}gsi;
		$ref=~s{<citation citation-type=\"book\">}{<citation citation-type=\"thesis\">}gsi;
		
	}
	elsif($ref=~m{Thesis}gs)
	{
		
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"thesis\">}gsi;
		
	}

	elsif($ref=~m{ Thesis}gsi)
	{
		
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"thesis\">}gsi;
		$ref=~s{<citation citation-type=\"book\">}{<citation citation-type=\"thesis\">}gsi;
		
	}
	
	elsif($ref=~m{<article\-title>} && $ref=~m{<source>}gsi)
	{
		
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"journal\">}gsi;
		
	}
	elsif($ref=~m{<journal\-title>} || $ref=~m{<source>}gsi)
	{
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"journal\">}gsi;
		
	}
	elsif($ref=~m{arxiv}gsi)
	{
		$ref=~s{<citation citation-type=\"([^\"]+)\">}{<citation citation-type=\"preprint\">}gsi;
		
	}
	elsif($ref=~m{<source>(.*?)Report}gsi)
	{
		#$ref=~s{<citation citation-type=\"([^\"]+)\">}{<citation citation-type=\"preprint\">}gsi;
		
	}
	
	else
	{
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"other\">}gsi;
		
	}

	my $ref1=$ref;

	if($ref1=~m{<thesis\-title>}gsi)
	{
		
		$ref=~s{<citation citation-type=\"journal\">}{<citation citation-type=\"thesis\">}gsi;
		$ref=~s{<citation citation-type=\"book\">}{<citation citation-type=\"thesis\">}gsi;
		
	}

	if($Publisher_Name eq "IOP Publishing") 
	{
		
		
		if($ref=~m{Report<\/source><x>([^\<]+)\<\/x><comm>}gsi)
		{
		$ref=~s{<citation citation-type=\"([^\"]+)\">}{<citation citation-type=\"report\">}gsi;
		
		}
	
		
	}
	$ref=~s{<book\-title>}{<source>}gsi;
	$ref=~s{<\/book\-title>}{<\/source>}gsi;

	
	

	
	return $ref;
}

sub Title_Format
{
	my $Title=shift;


	$Title=~s{<\/bold> <\!\-\-([^\>]+)\><bold>}{ <\!\-\-$1\>}gsi;
	$Title=~s{<\/bold><\!\-\-([^\>]+)\><bold>}{ <\!\-\-$1\>}gsi;
	$Title=~s{<\/bold><\!\-\-([^\>]+)\> <bold>}{ <\!\-\-$1\>}gsi;
	$Title=~s{<\/italic> <\!\-\-([^\>]+)\><italic>}{ <\!\-\-$1\>}gsi;
	$Title=~s{<\/italic><\!\-\-([^\>]+)\><italic>}{ <\!\-\-$1\>}gsi;
	$Title=~s{<\/italic><\!\-\-([^\>]+)\> <italic>}{ <\!\-\-$1\>}gsi;
	
	
	my $Count_B=$Title=~s{<bold>}{<bold>}gsi;
	if($Count_B eq 1)
	{
		
		$Title=~s{<title><bold>(.*?)<\/bold>([\s\.]?)<\/title>}{<title>$1$2<\/title>}gsi;
		$Title=~s{<title>(\s?)<bold>(.*?)<\/bold>([\s\.]?)<\/title>}{<title>$1$2$3<\/title>}gsi;
		$Title=~s{<title(\d+)><bold>(.*?)<\/bold>([\s\.]?)<\/title\1>}{<title>$2$3<\/title>}gsi;
		$Title=~s{<subtitle><bold>(.*?)<\/bold>([\s\.]?)<\/subtitle>}{<subtitle>$1$2<\/subtitle>}gsi;
		$Title=~s{<article\-title><bold>(.*?)<\/bold>([\s\.]?)<\/article\-title>}{<article\-title>$1$2<\/article\-title>}gsi;
		$Title=~s{<article\-title>(\s?)<bold>(.*?)<\/bold>([\s\.]?)<\/article\-title>}{<article\-title>$1$2$3<\/article\-title>}gsi;
		
		
	}

	my $Count_I=$Title=~s{<italic>}{<italic>}gsi;

		
	if($Count_I eq 1)
	{
		$Title=~s{<title><italic>(.*?)<\/italic>([\s\.]?)<\/title>}{<title>$1$2<\/title>}gsi;
		$Title=~s{<title><italic>(.*?)<\/italic><\/title>}{<title>$1<\/title>}gsi;
		$Title=~s{<title>(\s?)<italic>(.*?)<\/italic>([\s\.]?)<\/title>}{<title>$1$2$3<\/title>}gsi;
		$Title=~s{<title(\d+)><italic>(.*?)<\/italic>([\s\.]?)<\/title\1>}{<title>$2$3<\/title>}gsi;
		$Title=~s{<subtitle><italic>(.*?)<\/italic>([\s\.]?)<\/subtitle>}{<subtitle>$1$2<\/subtitle>}gsi;
		
	}

	
	return $Title;
	
}



