sub Box
{
	my $Box=shift;

	
	
	$Box=~s{<box(\d+)\/>}{<box$1>}gsi;

	if($Box=~m{<box(\d+)>}gsi)
	{
		
		$Box=~s{<\/boxed\-text>}{\n<box1><empty><\/boxed\-text>}gsi;
	}

	

my @body;
my ($lvl,$prevlvl);
$lvl = $prevlvl = 0;
 
@body = split ('\n', $Box);

foreach my $line (@body)
{
	if($line =~ /<box([0-9])>/)
	{
                $lvl=ord($1);
		
                my $closetag = '';
                for(my $i=$prevlvl;$i>=$lvl;$i--)
                {
                        my $l = chr($i);
                        $closetag = $closetag . "\n</box$l>";
			
                }
                $line = $closetag . "\n" . $line;
                $prevlvl = $lvl;
        }
}

my $lines =join("\n",@body);
$Box=$lines;



my $sec ='1';
$Box=~s{<box(\d+)><empty>}{}gsi;

$Box=~s/<box(\d+)>/'<sec id="b'.$sec++.'">'/segi;

$Box=~s{<\/box(\d+)>}{<\/sec>}gsi;


	return $Box;
}

	
	
