sub upper
{
	my($string) = @_;

	my @exception_words = ('A', 'The', 'If', 'Is', 'It', 'Of', 'Our', 'An','On', 'In', 'But', 'With', 'Has', 'Had', 'Have','And','To');
	lc($string);
	$string =~ s/([\w']+)/\u\L$1/g;
	foreach(@exception_words)
	{
		$string =~ s/\b$_\b/lc($_)/ge;
	}
	
# Uppercase the first letter
	$string =~ s/(.)/\u$1/;

	$string=~s{\&(\w+)\;}{\&\l$1\;}gsi;
	return $string;
}
