sub Abstract
{
	my $Abstract=shift;

	

	$Abstract=~s{<\/p>\n<p>}{<\/p><p>}gsi;
	$Abstract=~s{<\/sec>\n<p>(.*?)<\/p>\n}{\n<p>$1<\/p><\/sec>}gsi;
	$Abstract=~s{<\/p><p>}{<\/p>\n<p>}gsi;
	$Abstract=~s{<sec><title><bold><italic>(.*?)</italic></bold>(&mdash;)</title>}{<sec><title>$1$2<\/title>}gsi;

	if($Tmp=~m{<publisher>\n<publisher-name>Lippincott Williams \&\#x0026; Wilkins</publisher-name>}gsi)
{

		
		
		$Abstract=~s{<\/p>\n<title>}{<\/p><\/abstract>\n<abstract>\n<title>}gsi;

		$Abstract=~s{<\/p><\/sec>\n<title>}{<\/p><\/sec><\/abstract>\n<abstract>\n<title>}gsi;


		

		$Abstract=~s{<abstract>\n<title>(Summary)}{<abstract abstract\-type="precis">\n<title>$1}gsi;
		$Abstract=~s{<abstract>\n<title>(Lay Summary)}{<abstract abstract\-type="precis">\n<title>$1}gsi;
		$Abstract=~s{<abstract>\n<title>(Key Point)}{<abstract abstract\-type="precis">\n<title>$1}gsi;
		$Abstract=~s{<abstract>\n<title>(Main Point)}{<abstract abstract\-type="precis">\n<title>$1}gsi;
		$Abstract=~s{<abstract>\n<title>(promotional text)}{<abstract abstract\-type="precis">\n<title>$1}gsi;
		
		
		
}


	$Abstract=~s{<p><\/p>}{}gsi;

if($Tmp=~m{<publisher>\n<publisher-name>OUP</publisher-name>}gsi || $Tmp=~m{<publisher>\n<publisher-name>Oxford University Press</publisher-name>}gsi || $Tmp=~m{<publisher>\n<publisher-name>Public Library of Science</publisher-name>}gsi || $Tmp=~m{<publisher>\n<publisher-name>Adi Health\+Wellness</publisher-name>}gsi)
{
		$Abstract=~s{<\/title>\n*<p>([\.\:]+)}{$1<\/title>\n<p>}gsi;

		$Abstract=~s{<\/title>\n*<p><bold>([\.\:\s]+)<\/bold>}{$1<\/title>\n<p>}gsi;	
		
		$Abstract=~s{<\/p>\n<title>}{<\/p><\/abstract>\n<abstract>\n<title>}gsi;

		$Abstract=~s{<\/p><\/sec>\n*<title>}{<\/p><\/sec><\/abstract>\n<abstract>\n<title>}gsi;

		$Abstract=~s{<abstract>\n*<\/abstract>}{}gsi;

		

		my $J1=$Jats_Type;

		if($J1 ne "jats")
		{
			$Abstract=~s{<abstract([^\>]+)\>}{<abstract>}gsi;

		my $Journal_Name1=$Journal_Name;
		
		if($Journal_Name1=~m{(AJCPAT|NEUONC|NOPRAC|NOAJNL)}gsi)
		{

			$Abstract=~s{<abstract>\n<title>(Key Point)}{<abstract abstract\-type="key-points">\n<title>$1}gsi;
		}
		elsif($Journal_Name1=~m{AOBPLA}gsi)
		{

			$Abstract=~s{<abstract>\n<title>(promotional text)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
		}

		elsif($Journal_Name1=~m{BEHECO}gsi)
		{
			

			$Abstract=~s{<abstract>\n<title>(Lay Summary)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
		}
		elsif($Journal_Name1=~m{ABMEDI}gsi)
		{
			

			$Abstract=~s{<abstract>\n<title>(Lay Summary)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
		}
		elsif($Journal_Name1=~m{(CLINID|OFIDIS)}gsi)
		{

			$Abstract=~s{<abstract>\n<title>(Lay Summary)}{<abstract abstract\-type="layperson">\n<title>$1}gsi;
			$Abstract=~s{<abstract>\n<title>(Summary)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
			
		}
		elsif($Journal_Name1=~m{(CARCIN|IBDJNL|INFDIS|JPIDSJ)}gsi)
		{

			$Abstract=~s{<abstract>\n<title>(Summary)(.*?)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
			
		}
		elsif($Journal_Name1=~m{CROCOL}gsi)
		{

			$Abstract=~s{<abstract>\n<title>(Lay Summary)}{<abstract abstract\-type="layperson">\n<title>$1}gsi;
			$Abstract=~s{<abstract>\n<title>(Summary)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
			
		}
		elsif($Journal_Name1=~m{(ANNBOT|INFDIS|JHERED|NICTOB|OCCMED|OFIDIS|PUBOPQ|AUKJNL|CONDOR|FAMPRJ|TBMEDI)}gsi)
		{

			$Abstract=~s{<abstract>\n<title>(Lay Summary)}{<abstract abstract\-type="layperson">\n<title>$1}gsi;

			

			$Abstract=~s{<abstract([^\>]*)\>\n<title>(Lay Summary)}{<abstract abstract\-type="layperson">\n<title>$2}gsi;
			
		}
		elsif($Journal_Name1=~m{EXBOTJ}gsi)
		{

			
			#Abstract=~s{<abstract>\n<title>(Highlight)}{<abstract abstract\-type="teaser">\n<title>$1}gsi;
			
		}


		
		$Abstract=~s{(<abstract abstract-type=\"teaser\">(.*?)<\/abstract>)}{&Teaser_Abstract($1)}gesi;

		
		}
		
		#$Abstract=~s{<abstract>\n<title>(Main Point)}{<abstract abstract\-type="precis">\n<title>$1}gsi;
		
}





if($Publisher_Name ne "IOP Publishing" || $Publisher_Name ne "OUP") 
{
	
	
	$Abstract=~s{<ref}{<absreference><ref}gsi;

	$Abstract=~s{<\/ref([^\>]*)\>}{<\/ref$1><\/absreference>}gsi;

	$Abstract=~s{<\/absreference>([^\<]+)\<absreference>}{$1}gsi;

	

	$Abstract=~s{<absreference>(.*?)<\/absreference>}{"<ref id=\"CIT000\"><citation citation-type=\"journal\">".&Reference($1)."</citation></ref>"}gesi;

	

	$Abstract=~s{(<citation citation-type=\"(.*?)\">(.*?)<\/citation>)}{&reftype($1)}gesi;

	
}

	return $Abstract;
	
}



sub Appendix
{
	my $Appendix=shift;

	$Appendix=~s{<lwwsec(\d+)\/>}{<sec$1>}gsi;

	if($Appendix=~m{<sec(\d+)>}gsi)
{
	my $Digit=$1;

	if($Digit eq 2)
	{
		$Appendix=~s{(<sec$Digit>)}{<sec1><title\/>\n<sec$Digit>}si;
		$Appendix=~s{<\/sec1>}{}si;
		
	}

	if($Digit eq 3)
	{
		$Appendix=~s{(<sec$Digit>)}{<sec1><title\/>\n<sec2><title\/>\n<sec$Digit>}si;
		$Appendix=~s{<\/sec2>}{}si;
		$Appendix=~s{<\/sec1>}{}si;
		
		
	}
}


	if($Appendix=~m{<sec(\d+)>}si)
	{
		$Appendix=~s{<\/app>}{<sec1><empty><\/app>}gsi;
	}

my @body1;
my ($lvl1,$prevlvl1);
$lvl1 = $prevlvl1 = 0;
 
@body1 = split ('\n', $Appendix);

foreach my $line (@body1)
{
	if($line =~ /<sec([0-9])>/)
	{
                $lvl1=ord($1);
		
                my $closetag = '';
                for(my $i=$prevlvl1;$i>=$lvl1;$i--)
                {
                        my $l = chr($i);
			
                        $closetag = $closetag . "\n</sec$l>";
			
                }
                $line = $closetag . "\n" . $line;
                $prevlvl1 = $lvl1;
        }
}

my $lines =join("\n",@body1);
$Appendix=$lines;

	$Appendix=~s{<sec(\d+)><empty>}{}gsi;

	$Appendix=~s/<sec(\d+)>/'<sec id="s'.$sec++.'">'/segi;

	$Appendix=~s{<\/sec(\d+)>}{<\/sec>}gsi;


	
	
	return $Appendix;
}


sub Entry
