	$Entry=~s{<break\/><list}{<list}gsi;
	$Entry=~s{<break\/><\/list}{<\/list}gsi;
	$Entry=~s{<break\/><\/p}{<\/p}gsi;


	
	return $Entry;
}

sub Table_Fn
{
	my $Fn=shift;
	
	my $Id=shift;

	$Fn=~s{\+}{\&\#x002B\;}gsi;

	$Fn=~s{ <\/tabfnxref>}{<\/tabfnxref> }gsi;

	$Fn=~s{ <\/tabfnxrefonline>}{<\/tabfnxrefonline> }gsi;

	
		
	$Fn=~s{<\/tabfnxref><tabfnxref>}{}gsi;
	$Fn=~s{<\/tabfnxrefonline><tabfnxrefonline>}{}gsi;

	$Fn=~s{<tabfnxref>(.*?)<\/tabfnxref>}{<tabfnxref><sup>$1<\/sup><\/tabfnxref>}gsi;
			
	$Fn=~s{<tabfnxref>(.*?)<\/tabfnxref>}{&Fn_Comma($1)}gesi;

	
	$Fn=~s{<tabfnxrefonline>(.*?)<\/tabfnxrefonline>}{&Fn_Comma1($1)}gesi;

	
	

	
	$Fn=~s{<sup><sup>}{<sup>}gsi;

	$Fn=~s{<\/sup><\/sup>}{<\/sup>}gsi;

		
	my $fn="Fn";

	my $Count_Fn='1';

	$Fn=~s{<\/tabfnxref><tabfnxref>}{}gsi;
	
	
	$Fn=~s{(<fn>(.*?)<\/fn>)}{&Fn($1,$Id,$Count_Fn++)}gesi;

		
	$Fn=~s{<sup><sup>}{<sup>}gsi;
	$Fn=~s{<\/sup><\/sup>}{<\/sup>}gsi;

	
	
	
	while($Fn=~m{<fn id=\"([^\"]+)\"><p><tabfn>(.*?)<\/tabfn>}gsi)
	{
		my $Xref=$1;
		my $Tab=$2;

		
		$Fn=~s{<tabfnxref>$Tab<\/tabfnxref>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab<\/xref>}gs;
		$Fn=~s{<tabfnxrefonline>$Tab<\/tabfnxrefonline>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab<\/xref>}gs;

		
		
	}

	while($Fn=~m{<fn id=\"([^\"]+)\"><p><tabfn>(.*?)<\/tabfn>}gsi)
	{
		my $Xref=$1;
		my $Tab=$2;

		
		
		$Fn=~s{<tabfnxref>$Tab([a-z])<\/tabfnxref>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab$1<\/xref>}gs;
		$Fn=~s{<tabfnxrefonline>$Tab([a-z])<\/tabfnxrefonline>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab$1<\/xref>}gs;

		
		
	}

	

	while($Fn=~m{<fn id=\"([^\"]+)\"><p><tabfn><sup>(.*?)<\/sup><\/tabfn>}gsi)
	{
		my $Xref=$1;
		my $Tab=$2;

		
		
		$Fn=~s{<tabfnxref>$Tab<\/tabfnxref>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab<\/xref>}gs;
		$Fn=~s{<tabfnxrefonline>$Tab<\/tabfnxrefonline>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab<\/xref>}gs;
		$Fn=~s{<tabfnxref>$Tab([a-z])<\/tabfnxref>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab$1<\/xref>}gs;
		$Fn=~s{<tabfnxrefonline>$Tab([a-z])<\/tabfnxrefonline>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab$1<\/xref>}gs;

		
		
	}

	
	my $Fn1=$Fn;

	

	$Fn1=~s{(<fn id=\"([^\"]+)\"><p><tabfn><sup>(\w+)\&ndash;(\w+)<\/sup>)}{&Fn_Ndash($1,$2,$3,$4)}gesi;

	
	
	while($Fn1=~m{<fn id=\"([^\"]+)\"><sup>(\w+)<\/sup>}gsi)
	{
		my $Xref=$1;
		my $Tab=$2;

		
		$Fn=~s{<tabfnxref>$Tab<\/tabfnxref>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab<\/xref>}gs;
		$Fn=~s{<tabfnxref><sup>$Tab<\/sup><\/tabfnxref>}{<xref ref-type=\"tabfn\" rid=\"$Xref\"><sup>$Tab<\/sup><\/xref>}gs;
		$Fn=~s{<tabfnxrefonline>$Tab<\/tabfnxrefonline>}{<xref ref-type=\"tabfn\" rid=\"$Xref\">$Tab<\/xref>}gs;
	}


	
	$Fn=~s{<tabfn>(.*?)<\/tabfn>}{$1}gsi;

	$Fn=~s{<\/sup><\/xref>\,(<xref ref-type=\"tabfn\" rid=\"([^\"]+)\"><sup>)}{<\/sup><\/xref><sup>\,<\/sup>$1}gsi;



	if($Publisher_Name eq "Oxford University Press") 
	{

	
	#$Fn=~s{<fn id=\"([^\"]+)\"><p><sup>([^\<]+)\</sup>\,</p></fn><fn id=\"([^\"]+)\"><p><sup>([^\<]+)\</sup>}{<fn id=\"$1\"><p><sup>$2,$4<\/sup>}gsi;

	}

	
	
	return $Fn;
}

sub Fn_Comma
{
	my $Fn=shift;

	my $Original=$Fn;


	
	

	
	$Fn=~s{<sup>}{}gsi;
	$Fn=~s{<\/sup>}{}gsi;
	$Fn=~s{<italic>}{}gsi;
	$Fn=~s{<\/italic>}{}gsi;
	$Fn=~s{<bold>}{}gsi;
	$Fn=~s{<\/bold>}{}gsi;
	

	$Fn=~s{(\d+)\&}{$1,\&}gsi;
	$Fn=~s{(\w+)\&}{$1,\&}gsi;
	$Fn=~s{\;\&}{\;,\&}gsi;
	$Fn=~s{\;(\d+)}{\;\,$1}gsi;
	$Fn=~s{\,\,}{\,}gsi;

	$Fn=~s{\&ast;,\&ast;}{\&ast;\&ast;}gs;
	$Fn=~s{\&Dagger;,\&Dagger;}{\&Dagger;\&Dagger;}gs;
	$Fn=~s{\&dagger;,\&dagger;}{\&dagger;\&dagger;}gs;
	$Fn=~s{\&sect;,\&sect;}{\&sect;\&sect;}gs;
	$Fn=~s{\&boxV;,\&boxV;}{\&boxV;\&boxV;}gs;
	$Fn=~s{\&Vert;,\&Vert;}{\&Vert;\&Vert;}gs;
	$Fn=~s{\&para;,\&para;}{\&para;\&para;}gs;
	$Fn=~s{\&num;,\&num;}{\&num;\&num;}gs;
	$Fn=~s{\&ast;,\&ast;}{\&ast;\&ast;}gs;

	
	
	
	if($Fn!~m{\&}si)
	{

		if($Original=~m{<sup><italic>}gsi)
		{
		$Fn=~s{<sup>}{}gsi;
		$Fn=~s{<\/sup>}{}gsi;
		$Fn=~s{([a-z])}{<sup><italic>$1<\/italic><\/sup>,}gsi;
		}
		elsif($Original=~m{<sup>}gsi)
		{
		$Fn=~s{<sup>}{}gsi;
		$Fn=~s{<\/sup>}{}gsi;
		
		$Fn=~s{([a-z])}{<sup>$1<\/sup>}gsi;
		
		}
		
		else
		{
			$Fn=~s{([a-z])}{$1}gsi;
		}
		$Fn=~s{\,$}{}gsi;
	}

	
	
	my @Xref=split(',',$Fn);

	my @X;

	foreach my $Value(@Xref)
	{
		$Value="<tabfnxref><sup>$Value<\/sup><\/tabfnxref>";


		push(@X,$Value);
	}

	my $Final_Xref;
	
	if($Original=~m{\,}gsi)
	{
	$Final_Xref=join(",",@X);
	}
	else
	{
	$Final_Xref=join("",@X);
	}

	
	
	return $Final_Xref;
}


