	foreach my $Value(@Foot)
	{

	$Value="<fn>$Value<\/p><\/fn>";
	
	

	push(@F,$Value);
	}
	my $Final_Foot=join("<tabfnxref",@F);

	$Final_Foot=~s{<tabfnxref<fn>>}{<fn><tabfnxref>}gsi;

	$Final_Foot=~s{<tabfnxref<fn>online>}{<fn><tabfnxrefonline>}gsi;

	$Final_Foot=~s{<fn><fn>}{<fn>}gsi;
	
	$Final_Foot=~s{<fn><fn><p></fn>}{<fn>}gsi;
	
	$Final_Foot=~s{<fn><p><\/p><fn}{<fn}gsi;

	$Final_Foot=~s{<fn><p><\/p><\/fn>}{}gsi;

	

	$Final_Foot=~s{<tabfnxref>(.*?)<\/tabfnxref>}{"<fn id=\"$Id$fn".$Count_Fn++."\"><p><tabfn><sup>$1<\/sup></tabfn>"}sgei;
	$Final_Foot=~s{<tabfnxrefonline>(.*?)\<\/tabfnxrefonline>}{"<fn id=\"$Id$fn".$Count_Fn++."\"><p><tabfn>$1</tabfn>"}sgei;

	

	
	$Final_Foot=~s{<fn><fn }{<fn }gsi;

	$Final_Foot=~s{<fn><p><fn }{<fn }gsi;

	$Final_Foot=~s{<\/fn><\/p><\/fn>}{<\/fn>}gsi;

	$Final_Foot=~s{<fn>}{"<fn id=\"$Id$fn".$Count_Fn++."\">"}sgei;
	
	return $Final_Foot;
	}


