	{
		
		$Uri="https:\/\/www\.$Uri";
	}
	
	$Uri=~s{http:\/\/www\.http:\/\/}{http://www.}gsi;

	$Uri=~s{http:\/\/www\.https:\/\/www\.}{https://www\.}gsi;

	$Uri=~s{http\:\/\/www\.https\:\/\/www\.}{https://www\.}gsi;

	$Uri=~s{http\:\/\/www\.https\:}{https\:}gsi;

	$Uri=~s{https:\/\/www\.http:\/\/}{http://www.}gsi;

