	my $End=shift;
	my $Second=shift;
	my $Ndash=shift;
	my @Array_Id;
	my @Data;

	for(my $i=$Start;$i<=$End;$i++)
	{
		push(@Array_Id,"I$i");
		push(@Data,"<duplicate><xref ref-type=\"fig\" rid=\"I$i\">$First$Ndash$Second<\/xref><\/duplicate>");
	}

	my $Final_Id=join(" ",@Array_Id);

	my $Final_Data=join("",@Data);

	

	$Final_Id="<xref ref-type=\"fig\" rid=\"$Final_Id\">$First$Ndash$Second<\/xref>$Final_Data";
	
	return $Final_Id;
}

