sub URL_Query
{
	my $Url=shift;
	
	$Url=~s{<uri([^\>]+)\>}{}gsi;	  
	$Url=~s{<\/uri>}{}gsi;

	$Url=~s{ \">}{ }gsi;
	
	return $Url;	  
	
}

sub Related
{
	my $Related=shift;

	$Related=~s{<ins>}{}gsi;

	$Related=~s{<\/ins>}{}gsi;

	$Related=~s{<del>(.*?)<\/del>}{}gsi;

	
	
	my ($Vol,$Fpage,$Issue,$Correct);

	if($Related=~m{<refvolumeNumber>([^\<]+)\<\/refvolumeNumber>}si)
	{
		$Vol=$1;
	}

	if($Related=~m{<refissueNumber>([^\<]+)\<\/refissueNumber>}si)
	{
		$Issue=$1;
	}

	if($Related=~m{<refpageFirst>([^\<]+)<\/refpageFirst>}si)
	{
		$Fpage=$1;
	}


	if($Subject=~m{Correction}si)
	{
		$Correct="corrected-article";
	}
	
	if($Subject=~m{Erratum}si)
	{
		$Correct="corrected-article";
	}

	

	$Related=~s{(<refpageFirst>(.*?)</refpageLast>)}{<related\-article related-article-type="$Correct" vol="$Vol" issue="$Issue" page="$Fpage" ext-link-type="pmc" id="$Fpage">$1<\/related\-article>}gsi;

	#if($Subject=~m{Notice of Retraction}si)
	#{
		
	
	#$Related=~s{(<refiddoi>(.*?)</refiddoi>)}{<related-article related-article-type="retracted-article" ext-link-type="doi" xlink:href="$1"><bold>$1<\/bold></related-article>}gsi;

	#}
	
	$Related=~s{<FMRelatedArticle>(.*?)<\/FMRelatedArticle>}{<p><related-article related-article-type="retracted-article" ext-link-type="doi" xlink:href="$1"><bold>$1<\/bold></related-article><\/p>}gsi;

	$Related=~s{(xlink\:href=\"([^\"]+)\")}{OUP_Related($1)}gesi;

	$Related=~s{\"<bold>(.*?)<\/bold>\"}{\"$1\"}gsi;

	$Related=~s{<ref(\w+)>}{}gsi;

	$Related=~s{<\/ref(\w+)>}{}gsi;

	
	
	
	return $Related;
}

sub Orchid
{
	my $Orchid=shift;
	my $Meta=shift;

	
	my $Given_name;
	my $Surname;
	if($Orchid=~m{<given\-names>(.*?)<\/given\-names>}gsi)
	{
		$Given_name=$1;
		$Given_name=~s{\s$}{}gsi;
	}

	if($Orchid=~m{<surname>(.*?)<\/surname>}gsi)
	{
		$Surname=$1;
		$Surname=~s{\s$}{}gsi;
	}

	while($Meta=~m{<author>(.*?)<\/author>}gsi)
	{
		my $Au=$1;
		
		
		if($Au=~m{<author\-name>$Given_name([\s\,]+)$Surname<\/author\-name>}si)
		{
			
			if($Au=~m{<author\-orcid>(\d([^\<]+))\<\/author\-orcid>}gsi)
			{
				my $Id=$1;
				

				$Orchid=~s{<\/contrib>}{<\?Orchid $Id\?><\/contrib>}gsi;
			}
		}
	}
	
	return $Orchid;
}

sub Citation
{
	my $Citation=shift;

	
	
	
my @entity;
my %entity;



if($Citation=~m{\:(\s?)(\[?)(\d+|\w+)}si)
{
	
	
	while($Citation=~m{\"(CIT([^\"]+))\"}gsi)
	{
	my $figname = $1;

	
	
        $entity{$figname}='';
        push(@entity,$figname);
	}

@entity =grep(!$entity{$_}++,@entity);
my $enty = join(",",sort { $a cmp $b }@entity);	



$Citation="<citationId>$enty<\/citationId>";
}




return $Citation;
}

sub Linking
{
	my $Id=shift;
	my $Citation=shift;

	
	
		
	my $Id1=$Id;

	my $Ci1=$Citation;

	$Ci1=~s{\&\#x(\w+);}{}gsi;
	$Ci1=~s{\&(\w+);}{}gsi;
	#$Ci1=~s{\-}{}gsi;
	
	
	my $Count=$Ci1=~s{([0-9][0-9][0-9][0-9])}{$1}gsi;

		
	if($Count eq "1")
	{
		
		my @Ref=split(",",$Id);

		foreach my $Value(@Ref)
		{

			
			
			$Value=~s{\:(.*?)$}{}si;
			if($Citation=~m{([\,\;]+)b$}si)
			{
				
				$Citation=~s{([\,\;]+)b$}{$1<xref ref-type=\"bibr\" rid=\"$Value\">b<\/xref>}gsi;
			}
			else
			{
				$Citation="<xref ref-type=\"bibr\" rid=\"$Value\">$Citation<\/xref>";    
			}

			
			$Citation=~s{,<xref ref-type="bibr" rid=\"([^\"]+)\">b</xref><\/xref>}{<\/xref>\,<xref ref-type="bibr" rid=\"$1\">b</xref>}gsi;
		}
		

		#if($Id1=~m{$Id1}gsi)
		#{
			
		#}
		#$Citation="<xref ref-type=\"bibr\" rid=\"$Id\">$Citation<\/xref>";    
	}
	else
	{

		
		
		my @Ref=split(",",$Id);

		foreach my $Value(@Ref)
		{
			
			
			if($Value=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;

			
			
			$Citation=~s{\Q$Year\E\,}{<xref ref\-type=\"bibr\" rid=\"CIT$I\">$Year<\/xref>\,}si;

			$Citation=~s{\Q$Year\E\;}{<xref ref\-type=\"bibr\" rid=\"CIT$I\">$Year<\/xref>\;}si;

			$Citation=~s{\Q$Year\E\:}{<xref ref\-type=\"bibr\" rid=\"CIT$I\">$Year<\/xref>\:}si;

			$Citation=~s{\Q$Year\E$}{<xref ref\-type=\"bibr\" rid=\"CIT$I\">$Year<\/xref>}si;

			$Citation=~s{\Q$Year\E\)$}{<xref ref\-type=\"bibr\" rid=\"CIT$I\">$Year<\/xref>\)}si;

			$Citation=~s{^([A-z])$}{<xref ref\-type=\"bibr\" rid=\"CIT$I\">$1<\/xref>}si;

			
			
			}

			
			
			
		}

		
		#$Citation=~s{((.*?)([a-z])([\,\s]+))(<xref ref-type=\"bibr\" rid=\"([^\"]+)\">)}{$5$1}si;

		
		my $CC=$Citation;

		if($CC!~m{<xref}gsi)
		{
		
		if($Citation=~m{([0-9][0-9][0-9][0-9])\s?\[([0-9][0-9][0-9][0-9])}si)
		{
			if($Id=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;
			$Citation="<xref ref-type=\"bibr\" rid=\"CIT$I\">$Citation<\/xref>";
			}
		}

		elsif($Citation=~m{\[([0-9][0-9][0-9][0-9])\]\s?([0-9][0-9][0-9][0-9])}si)
		{
			if($Id=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;
			$Citation="<xref ref-type=\"bibr\" rid=\"CIT$I\">$Citation<\/xref>";
			}

			
		}

		elsif($Citation=~m{([0-9][0-9][0-9][0-9])\]\s?([0-9][0-9][0-9][0-9])}si)
		{
			if($Id=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;
			$Citation="<xref ref-type=\"bibr\" rid=\"CIT$I\">$Citation<\/xref>";
			}

			
		}

		elsif($Citation=~m{([0-9][0-9][0-9][0-9][a-z])\s?\[([0-9][0-9][0-9][0-9])\]}si)
		{
			if($Id=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;
			$Citation="<xref ref-type=\"bibr\" rid=\"CIT$I\">$Citation<\/xref>";
			}

			
		}

		elsif($Citation=~m{[0-9][0-9][0-9][0-9]\&ndash;(\d+)}si)
		{
			if($Id=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;
			$Citation="<xref ref-type=\"bibr\" rid=\"CIT$I\">$Citation<\/xref>";
			}

			
		}

		elsif($Citation=~m{<italic>([a-z])<\/italic>}si)
		{
			if($Id=~m{CIT(\d+)\:(.*)}si)
			{
			my $Year=$2;
			my $I=$1;
			$Citation="<xref ref-type=\"bibr\" rid=\"CIT$I\">$Citation<\/xref>";
			}

			
		}

		
		
		

		
		
		$Citation=~s{((.*?))(<xref ref-type=\"bibr\" rid=\"([^\"]+)\">)}{$3$1}si;

		}

		
	}




	my $Cit=$Citation;

	$Cit=~s{<xref ref-type=\"bibr\" rid=\"([^\"]+)\">(.*?)<\/xref>}{}gsi;

	my $Cit1=$Cit;

	$Cit1=~s{\&\#x(\w+);}{}gsi;

	
	
	while($Cit1=~m{(([0-9][0-9][0-9][0-9])(\w?))}gsi)
	{
		

		my $Va=$1;

		
		
		$Citation=~s{$Va}{<xref ref-type=\"bibr\" rid=\"000\">$Va<\/xref>}gsi;

		
	}

	

		#$Citation=~s{(\,)(\s?)([0-9][0-9][0-9][0-9])$}{$1$2<xref ref-type=\"bibr\" rid=\"000\">$3<\/xref>}gsi;

		#$Citation=~s{(\,)(\s?)\[([0-9][0-9][0-9][0-9])$}{$1$2\[<xref ref-type=\"bibr\" rid=\"000\">$3<\/xref>}gsi;

		#$Citation=~s{(\,)(\s?)\(([0-9][0-9][0-9][0-9])$}{$1$2\(<xref ref-type=\"bibr\" rid=\"000\">$3<\/xref>}gsi;
		
	
	
	return $Citation;
}

sub Sec_Title
{
	my $Title=shift;
	$Title=~s{<del>(.*?)<\/del>}{}gsi;
	$Title=~s{<ins>}{}gsi;
	$Title=~s{<\/ins>}{}gsi;
	return $Title;
}

sub Table_Wrap
{
	my $Table=shift;
	my $Id;
	if($Table=~m{<table\-wrap id=\"T([^\"]+)\"}gsi)
	{
		$Id=$1;
		$Id=~s{^(\d)$}{000$1}si;
		$Id=~s{^(\d\d)$}{00$1}si;
		$Id=~s{^(\d\d\d)$}{0$1}si;
		
	}
	
	$Table=~s{<\/table\-wrap>}{<graphic xlink:href="$FileName\_T$Id.tif"/>\n</table-wrap>}gsi;
	return $Table;
}


sub Fn_Note
{

	my $Note=shift;
	my $Type=shift;

	

	my $Count=$Note=~s{<Affxref>}{<Affxref>}gsi;
	my $Count1=$Note=~s{<Affxrefonline>}{<Affxrefonline>}gsi;

	if($Count gt 1)
	{
	$Note=~s{(\s)<AffXref>([^\<]+)\</AffXref>}{<\/p><\/fn>\n<fn id=\"\" fn\-type=\"$Type\"><p><Affxref>$2<\/Affxref>}gsi;
	}

	if($Count1 gt 1)
	{
	$Note=~s{(\s)<AffXrefonline>([^\<]+)\</AffXrefonline>}{<\/p><\/fn>\n<fn id=\"\" fn\-type=\"$Type\"><p><Affxrefonline>$2<\/Affxrefonline>}gsi;
	}

	return $Note;
}

