	$Contrib=~s{<fmaffFax>(.*?)<\/fmaffFax>}{<aff><fax>$1<\/fax><\/aff>}gsi;
	$Contrib=~s{<fmaffPhone>(.*?)<\/fmaffPhone>}{<phone>$1<\/phone>}gsi;
