	$Contrib=~s{<fmcorrgivenname>(.*?)<\/fmcorrgivenname>(\s?)([\,\;\:]+)(\s?)<fmcorrgivenname>(.*?)<\/fmcorrgivenname>}{<fmcorrgivenname>$1$2$3$4$5<\/fmcorrgivenname>}gsi;
	

	
	$Contrib=~s{<fmauGivenName>\s<\/fmauGivenName>}{}gsi;
