	$Contrib=~s{<fmcorrGivenName>([^\<]+)\</fmcorrGivenName>(\s?)<commentReference/>(\s?)<fmcorrGivenName>([^\<]+)</fmcorrGivenName>}{<fmcorrGivenName>$1$4<\/fmcorrGivenName><commentReference/>}gsi;

	$Contrib=~s{<fmausurName>([^\<]+)\</fmausurName>(\s?)<commentReference/>(\s?)<fmausurName>([^\<]+)</fmausurName>}{<fmausurName>$1$4<\/fmausurName><commentReference/>}gsi;

	$Contrib=~s{<fmcorrsurName>([^\<]+)\</fmcorrsurName>(\s?)<commentReference/>(\s?)<fmcorrsurName>([^\<]+)</fmcorrsurName>}{<fmcorrsurName>$1$4<\/fmcorrsurName><commentReference/>}gsi;



	$Contrib=~s{<fmauGivenName>([^\<]+)\</fmauGivenName>(\s?)<commentReference(\d+)\/>(\s?)<fmauGivenName>([^\<]+)</fmauGivenName>}{<fmauGivenName>$1$5<\/fmauGivenName><commentReference$3\/>}gsi;

	$Contrib=~s{<fmauGivenName>([^\<]+)\</fmauGivenName>(\s?)<query>(.*?)\<\/query>(\s?)<fmauGivenName>([^\<]+)</fmauGivenName>}{<fmauGivenName>$1$5<\/fmauGivenName><query>$3<\/query>}gsi;

	
	
	#$Contrib=~s{<fmaucollab>([^\<]+)\</fmaucollab>(\s?)<query>(.*?)\<\/query>(\s?)<fmaucollabe>([^\<]+)</fmaucollab>}{<fmaucollab>$1$5<\/fmaucollab><query>$3<\/query>}gsi;

	
	
	$Contrib=~s{<fmcorrGivenName>([^\<]+)\</fmcorrGivenName>(\s?)<commentReference(\d+)\/>(\s?)<fmcorrGivenName>([^\<]+)</fmcorrGivenName>}{<fmcorrGivenName>$1$5<\/fmcorrGivenName><commentReference$3\/>}gsi;

	$Contrib=~s{<fmcorrGivenName>([^\<]+)\</fmcorrGivenName>(\s?)<query>(.*?)<\/query>(\s?)<fmcorrGivenName>([^\<]+)</fmcorrGivenName>}{<fmcorrGivenName>$1$5<\/fmcorrGivenName><query>$3<\/query>}gsi;

	$Contrib=~s{<fmausurName>([^\<]+)\</fmausurName>(\s?)<commentReference(\d+)/>(\s?)<fmausurName>([^\<]+)</fmausurName>}{<fmausurName>$1$5<\/fmausurName><commentReference$3/>}gsi;

	
	
