	$Contrib=~s{<fmcorrsurName>([^\<]+)\</fmcorrsurName><\/contrib>(\s?)<query>(.*?)<\/query>(\s?)<contrib contrib-type="author" corresp="yes"><fmcorrsurName>([^\<]+)</fmcorrsurName>}{<fmcorrsurName>$1$5<\/fmcorrsurName><query>$3<\/query>}gsi;

	
	
