	$Contrib=~s{<fmcorrDegree>(.*?)<\/fmcorrDegree>(\s?)\.}{<fmcorrDegree>$1$2\.<\/fmcorrDegree>}gsi;
	
	$Contrib=~s{<fmauDegree>(.*?)<\/fmauDegree>(\s?)([\,\;\:]+)(\s?)<fmauDegree>(.*?)<\/fmauDegree>}{<fmauDegree>$1$2$3$4$5<\/fmauDegree>}gsi;

	$Contrib=~s{<fmauDegree>(.*?)<\/fmauDegree>(\s?)([\,\;\:]+)(\s?)<fmauDegree>(.*?)<\/fmauDegree>}{<fmauDegree>$1$2$3$4$5<\/fmauDegree>}gsi;

	$Contrib=~s{<fmcorrDegree>(.*?)<\/fmcorrDegree>(\s?)([\,\;\:]+)(\s?)<fmcorrDegree>(.*?)<\/fmcorrDegree>}{<fmcorrDegree>$1$2$3$4$5<\/fmcorrDegree>}gsi;

	$Contrib=~s{<fmcorrDegree>(.*?)<\/fmcorrDegree>(\s?)([\,\;\:]+)(\s?)<fmcorrDegree>(.*?)<\/fmcorrDegree>}{<fmcorrDegree>$1$2$3$4$5<\/fmcorrDegree>}gsi;


