sub Disp
{
	my $Disp=shift;
	
	my $M="$Cats.$Cats1.$Cats2";


	my $ID;
	if($Disp=~m{<disp-formula id=\"([^\"]+)\">}gsi)
	{
		$ID=$1;
	}
	if($Disp=~m{<inline\-formula id=\"([^\"]+)\">}gsi)
	{
		$ID=$1;
	}

	
	
	
	if($M=~m{<$ID>\n*(<mml\:math([^\>]*)\>(.*?)<\/mml\:math>)\n*<\/$ID>}si)
	{

	my $M=$1;

	

	$M=~s{<mml:munder over>}{<mml:munderover>}gsi;
	$M=~s{<none\/>}{<mml:none\/>}gsi;
	$M=~s{<none\(noneclose\)}{<mml:none\/>}gsi;
	$M=~s{<mml\:mprescripts\(mprescriptsclose\)}{<mml\:mprescripts\/>}gsi;
	
	
	$Disp=~s{<disp\-formula([^\>]*)\>}{<disp\-formula$1>\n$M}si;

	$Disp=~s{<inline\-formula([^\>]*)\>}{<inline\-formula$1>\n$M}si;

	}

	
	if($Publisher_Name ne "IOP Publishing" || $Publisher_Name ne "OUP") 
	{
		$Disp=~s{xlink\:href=\"2DM}{xlink\:href=\"TDM}
	}
	
	
	
	return $Disp;
	
}

