		$ID=~s{\&Prime\;}{prime}gsi;
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;
	}

	
	

	if($Disp=~m{<label>(\()(\d+)\.(\d+)(\w)([^\<]+)\<\/label>}gsi)
	{
		my $ID="$2\.$3$4";
		
		$ID=~s{\&Prime\;}{prime}gsi;
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	if($Disp=~m{<label>(\()(\d+)\.(\d+)\.(\d+)([^\<]+)\<\/label>}gsi)
	{
		my $ID="$2\.$3\.$4";

		
		
		$ID=~s{\&Prime\;}{prime}gsi;
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	

	if($Disp=~m{<label>(\()([A-Z])\.(\d+)\.(\d+)([^\<]+)\<\/label>}gsi)
	{
		my $ID="$2\.$3\.$4";

		
		
		$ID=~s{\&Prime\;}{prime}gsi;
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	if($Disp=~m{<label>(\()([A-z])(\d+)\.(\d+)(\))<\/label>}gsi)
	{
		my $ID="$2$3\.$4";
		
		$ID=~s{\&Prime\;}{prime}gsi;
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;
	}


	
	
	if($Disp=~m{<label>(\()(\d+)([A-z]) and ([^\<]+)\<\/label>}gsi)
	{
		my $ID="$2";
		
		$ID=~s{\&Prime\;}{prime}gsi;
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;
	}

	
	#if($Disp=~m{<label>(\()(\d+)\.(\d+)([^\<]+)\<\/label>}gsi)
	#{
		#my $ID="$2\.$3";
		#$ID=~s{\&Prime\;}{prime}gsi;
		
		#$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	#}

	

	


	

	if($Disp=~m{<label>(\[)([A-z]+)\.(\d+)([^\<]+)\<\/label>}gsi)
	{
		my $ID="$3";
		$ID=~s{\&Prime\;}{prime}gsi;

			
		
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}
	
	if($Disp=~m{<label>(\()([A-Z]+)\.(\d+)([^\<]+)\<\/label>}gsi)
	{
		my $ID="$2\.$3";
		$ID=~s{\&Prime\;}{prime}gsi;
		
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	if($Disp=~m{<label>([A-z]+) (\d+)<\/label>}gsi)
	{
		my $ID="$2";
		$ID=~s{\&Prime\;}{prime}gsi;

			
		
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	

	if($Disp=~m{<label>(\()([A-z])\.(\d+)(\w)(\))<\/label>}si)
	{
		my $ID="$2\.$3$4";

		
		$ID=~s{\&Prime\;}{prime}gsi;

			
		
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	if($Disp!~m{<label>}si)
	{
		
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula>}si;
	}
	
	
	if($Disp=~m{<label>(\()(\d+)([A-z])\,([^\<]+)\<\/label>}si)
	{
		
		my $ID="$2";
		
		
		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;
		
