		$Label=~s{<disp\-formula id=\"([^\"]+)\">}{<disp\-formula id=\"M$ID\">}si;

		
	}

	$Label=~s{<disp\-formula id=\"Mcstr\. \((\d+)\">}{<disp\-formula id=\"MT$1\">}gsi;
	
	return $Label;
}

sub IOP_Linking
{
	my $Linking=shift;

	my $Ref_Id=shift;

	my $Reference_Tmp=$Tmp;

	

	if($Reference_Tmp=~m{<ref id=\"$Ref_Id\"([^\>]*)\>(.*?)<\/ref>}gsi)
	{

	my $Ref=$2;

	if($Ref=~m{<year>([^\<]+)\<\/year>}gsi)
	{
		my $Ref_Year=$1;
		
	$Linking=~s{<xref ref\-type=\"bibr\" rid=\"($Ref_Id)\">(.*?)($Ref_Year)([^\<]*)\<\/xref>}{$2<xref ref\-type=\"bibr\" rid=\"$1\">$3$4<\/xref>}gsi;

	$Linking=~s{<xref ref\-type=\"bibr\" rid=\"([^\"]+)\">(.*?)([0-9][0-9][0-9][0-9])([^\<]*)\<\/xref>}{$2<xref ref\-type=\"bibr\" rid=\"$1\">$3$4<\/xref>}gsi;
	
	}
	

	else
	{
		
		$Linking=~s{<xref ref\-type=\"bibr\" rid=\"([^\"]+)\">(.*?)([0-9][0-9][0-9][0-9])([^\<]*)\<\/xref>}{$2<xref ref\-type=\"bibr\" rid=\"$1\">$3$4<\/xref>}gsi;
	}
	
	
	}
	
	
	return $Linking;
}

sub Disp_Xref
{
	my $Disp=shift;
	my $Tmp=shift;

	if($Disp=~m{M(\d+)[A-z]}gsi)
	{
		if($Tmp=~m{<disp\-formula id="$Disp">}gsi)
		{
			$Disp="<xref ref\-type=\"disp\-formula\" rid=\"$Disp\">";
		}
		else
		{
			$Disp=~s{M(\d+)[A-z]}{M$1}gsi;

			$Disp="<xref ref\-type=\"disp\-formula\" rid=\"$Disp\">";
		}
	}
	

	elsif($Disp=~m{^M(\d+)$}gsi)
	{
		if($Tmp=~m{<disp\-formula id="$Disp">}gsi)
		{
			$Disp="<xref ref\-type=\"disp\-formula\" rid=\"$Disp\">";
		}
		else
		{
			$Disp=~s{M(\d+)}{M$1a}gsi;

			

			$Disp="<xref ref\-type=\"disp\-formula\" rid=\"$Disp\">";
		}
	}
	else
	{
		$Disp="<xref ref\-type=\"disp\-formula\" rid=\"$Disp\">";
	}
	
	return $Disp;
}


