sub Appendix_Equ
{
	my $Appendix=shift;

	my $Tmp=shift;

	
	my $App1=$Appendix;
	while($App1=~m{<xref ref\-type=\"fn\" rid=\"([^\"]+)\">}gsi)
	{
		my $Id=$1;
		
		if($Tmp=~m{(<fn(\d?) fn\-type=\"fn\" id=\"$Id\">(.*?)<\/fn>)}gsi)
		{
			my $Fn=$1;

			

			$Appendix=~s{(<xref ref\-type=\"fn\" rid=\"$Id">(.*?)<\/xref>)}{$1<appfn>$Fn<\/appfn>}si;
		}
		
	}

	
	
	my $App=$Appendix;

	my $Countapp1="1";


	

	while($Appendix=~m{(<disp\-formula([^\>]+)\>(.*?)<\/disp\-formula>|<num_parts>(.*?)<\/num_parts>)}gsi)
	{

		my $Display=$1;

		
	}


	

	
	

	
	
	while($App=~m{<label>\((\d+)(\.?)(\d*)(a?)\)</label></disp\-formula>}gsi)
	{
		my $Label="$1$2$3$4";

		

		
		
		push(@Appendix_Tmp,"$Label\t$App_Count\.$Countapp1$2$4");
		$Countapp1++;
	}
	
	
	my $Countapp="1";

	my $Countapp2="1";

	
	
	
	$Appendix=~s{<label>\((\d+)(\.?)(\d*)(a?)\)\</label></disp\-formula>}{"<set>$1$2$3$4<\/set><label>\($App_Count\.".$Countapp++."$4\)</label></disp\-formula>"}gesi;

	
	

	my $App3=$Appendix;
	my $App2=$Appendix;

	

	
	
	while($App2=~m{<set>(\d+)(\.?)(\d*)(a?)<\/set><label>\((\w)\.(\d+)(a?)\)\</label></disp\-formula>}gsi)
	{
		my $Digit="$1$2$3";

		

			
		my $A=$6;

		
		
		while($App3=~m{<label>\($Digit([a-z])\)\</label></disp\-formula>}gsi)
		{
			
			
		$Appendix=~s{<label>\($Digit([a-z])\)\</label></disp\-formula>}{<label>\($App_Count\.$A$1\)</label></disp\-formula>}s;

		
		push(@Appendix_Tmp,"$Digit$1\t$App_Count\.$A$1");

		}
	}

	

	$Appendix=~s{<set>([^\<]+)\<\/set>}{}gsi;
	
	$Appendix=~s{<sec id=\"([^\"]+)\"><label>(\d+)\.(\d+)\.<\/label>}{<sec id=\"$1\"><label>$App_Count\.$3\.<\/label>}gsi;
	$Appendix=~s{<sec id=\"([^\"]+)\"><label>(\d+)\.(\d+)\.(\d+)\.<\/label>}{<sec id=\"$1\"><label>$App_Count\.$3\.$4\.<\/label>}gsi;
	$App_Count++;

	
	
	$Appendix=~s{(<disp\-formula([^\>]*)\>(.*?)<\/disp\-formula>)}{&Disp_ID($1)}gesi;

	my $App1=$Appendix;
	if($App1=~m{<sec id=\"([^\"]+)\"><title/>}si)
	{
		$Appendix=~s{<sec id=\"([^\"]+)\"><title/>}{}gsi;
		$Appendix=~s{</sec>\n*</app>}{<\/app>}gsi;
	}

	

	while($App1=~m{<sec id=\"([^\"]+)\"><label>(.*?)<\/label>}gsi)
	{
		push(@Appendix_T,"$1\t$2");
	}


	
	
	return $Appendix;
}

sub Section_Para
{
	my $Section=shift;

	

	
	$Section=~s{<p content\-type=\"indent\">}{<p content-type="flush left">}si;
	$Section=~s{<p content\-type=\"indent\">([a-z])}{<p content-type="flush left">$1}gs;
	$Section=~s{<p content\-type=\"indent\">\(([a-z])}{<p content-type="flush left">\($1}gs;
	$Section=~s{<p content\-type=\"indent\">\[([a-z])}{<p content-type="flush left">\[$1}gs;
	$Section=~s#<p content\-type=\"indent\">\{([a-z])#<p content-type="flush left">\{$1#gs;
	#$Section=~s{<p content\-type=\"indent\"><inline\-formula}{<p content-type="flush left"><inline\-formula}gs;
	#$Section=~s{<p content\-type=\"indent\"><italic>\&(\w+)}{<p content-type="flush left"><italic>\&$1}gs;
	#$Section=~s{<p content\-type=\"indent\">\&(\w+)}{<p content-type="flush left">\&$1}gs;
	$Section=~s{<p content\-type=\"indent\">\&lt;noindent\/\&gt;(\s?)}{<p content-type="flush left">}gsi;
	$Section=~s{<p>\&lt;noindent\/\&gt;(\s?)}{<p content-type="flush left">}gsi;
	my $Sec_Count=$Section=~s{<sec}{<sec}gsi;

	if($Sec_Count gt 1)
	{
		$Section=~s{(<sec ([^\>]+)\>([^\n]+)\n)<p content\-type=\"indent\">}{$1<p content\-type=\"flush left\">}gsi;
	}
	

	
	return $Section;
}


