	$Email=~s{<\/email>}{<\/ext\-link>}gsi;

	$Email=~s{</ext\-link>, <ext\-link}{</ext\-link><x>, <\/x><ext\-link}gsi;
	
	return $Email;
}

sub Contrib_Email
{
