		if($Surname=~m{\&lt\;clink\&gt\;(\d+)\&lt\;\/clink\&gt;}gsi)
		{
			my $ID=$1;

			
			
			$Contrib=~s{<\/contrib>}{<xref ref\-type=\"aff\" rid="em$ID"/><\/contrib>}gsi;
		}
	}


	
	$Contrib=~s{<x> </x></name>(<xref([^\>]+)\>)<x>and </x>}{</name>$1<x> and </x>}gsi;
			
	$Contrib=~s{<x>([^\<]+)\<\/x><\/name>(.*?)<x>([^\<]+)\<\/x><\/contrib>}{<\/name>$2<x>$1$3<\/x><\/contrib>}gsi;

	$Contrib=~s{<x>\, <\/x><\/name>(<xref([^\>]+)\>)<\/contrib>}{<\/name>$1<x>\, <\/x><\/contrib>}gsi;

	
	
	$Contrib=~s{<x>([^\<]+)\<\/x>(<xref([^\>]+)\>)</contrib>}{$2<x>$1<\/x><\/contrib>}gsi;

	$Contrib=~s{<x>\, <\/x>(<xref([^\>]+)\>)<\/contrib>}{$1<x>\, <\/x><\/contrib>}gsi;

	$Contrib=~s{\&lt\;clink\&gt\;(\d+)\&lt\;\/clink\&gt;}{}gsi;

	#$Contrib=~s{<x>([^\<]+)\<\/x><\/name>(.*?)<\/contrib>}{<\/name>$2<x>$1$3<\/x><\/contrib>}gsi;
	
	return $Contrib;
}

