sub Statement
{
	my $Statement=shift;

	
	
	
	
	

	if($Statement=~m{<disp}gsi)
	{
		#$Statement=~s{<p content-type="indent"><italic>(.*?)<\/italic>}{<p content\-type=\"indent\">$1}si;
		#$Statement=~s{<p content-type="indent"><italic>}{<p content\-type=\"indent\">}si;
		#$Statement=~s{<\/italic><\/p>\n*<\/statement>}{<\/p>\n<\/statement>}gsi;
	}

	
	my $Sta=$Statement;



	my $Sta1=$Statement;

	my @St_Fig;
	
	while($Sta=~m{(<fig ([^\>]+)\>(.*?)<\/fig>)}gsi)
	{
		push(@St_Fig,$1);
	}

	my $Final_Figure=join("\n",@St_Fig);
	$Statement=~s{(<fig ([^\>]+)\>(.*?)<\/fig>)}{}gsi;

	

	
	$Statement=~s{<\/statement1>}{<\/statement1>\n$Final_Figure}gsi;

	if($Statement=~m{<statement(\d+)>(\n*)<label>Proof}gsi)
	{
		my $ST_No=$1;

		
		
		$Statement=~s{<\/p>\n*<\/statement$ST_No>}{ \&\#x25A1\;<\/p><\/statement$ST_No>}si;
		$Statement=~s{<\/list>\n*<\/statement$ST_No>}{ \&\#x25A1\;<\/list>\n<\/statement$ST_No>}si;
		$Statement=~s{\&squ; \&\#x25A1;}{\&squ;}gsi;
		$Statement=~s{\&\#x25A0\;(\s?)\&\#x25A1\;}{\&\#x25A0\;}gsi;

		
		
	}

	

	my @St_Tab;
	
	while($Sta1=~m{(<table\-wrap([^\>]*)\>(.*?)<\/table\-wrap>)}gsi)
	{
		push(@St_Tab,$1);
	}

	my $Final_Table=join("\n",@St_Tab);

	
	$Statement=~s{(<table\-wrap([^\>]*)\>(.*?)<\/table\-wrap>)}{}gsi;
	$Statement=~s{<\/statement1>}{<\/statement1>\n$Final_Table}gsi;

		
	$Statement=~s{\n{1,}}{\n}gsi;

	
	
	$Statement=~s{<\/disp\-formula>\n<disp\-formula}{<\/disp\-formula><disp\-formula}gsi;
	$Statement=~s{<\/p>\n(<disp\-formula([^\>]*)\>(.*?)<\/disp\-formula>)\n}{\n$1<\/p>\n}gsi;
	$Statement=~s{<\/disp\-formula><disp\-formula}{<\/disp\-formula>\n<disp\-formula}gsi;
	$Statement=~s{<\/list>\n<list}{<\/list><list}gsi;

	#$Statement=~s{<\/p>\n(<list1([^\>]*)\>(.*?)<\/list1>)}{\n$1<\/p>}gsi;
	
	
	
	#$Statement=~s{<\/list><\/p>\n<\/list\-item>\n<\/list>\n}{<\/list>\n<\/list\-item>\n<\/list><\/p>\n}gsi;

	
	
	$Statement=~s{<\/disp\-formula><disp\-formula}{<\/disp\-formula>\n<disp\-formula}gsi;
	$Statement=~s{<\/list><list}{<\/list>\n<list}gsi;

	$Statement=~s{</italic>(<xref([^\>]+)\>(.*?)<\/xref>)<italic>}{$1}gsi;

	
	my $St_Count=$Statement=~s{<statement}{<statement}gsi;

	if($St_Count ge "2")
	{

		
		
	$Statement=~s{<\/p>\n*<statement2>(.*?)<\/statement2>}{\n<statement2>$1<\/statement2><\/p>}gsi;

	$Statement=~s{<\/p>\n*<Remove_Statement_Label>(.*?)<\/Remove_Statement_Label>\n*<statement2>(.*?)<\/statement2>}{\n<Remove_Statement_Label>$1<\/Remove_Statement_Label><statement2>$2<\/statement2><\/p>}gsi;

	
	
	}

	

	$Statement=~s{<statement(\d+)}{<statement}gsi;

	$Statement=~s{<\/statement(\d+)}{<\/statement}gsi;

	
		
	if($Statement=~m{\&lt;IOP_Alpha\&gt\;}si)
	{
		
		my $Statement_Data=$Statement;
		$Statement=~s{<statement([^\>]*)\>\n*<label>(\w+) (\d+)([^\>]*)\<\/label><p content\-type=\"indent\">\&lt;Iop_Alpha\&gt;}{<statement$1><label>$2 $Sta_Alpha_Count$4<\/label><p content\-type=\"indent\">}gsi;
		if($Statement_Data=~m{<statement content\-type=\"([^\"]+)\" id=\"([^\"]+)\">\n*<label>(\w+) (\d+)([^\>]*)\<\/label><p content\-type=\"indent\">\&lt;Iop_Alpha\&gt;}gsi)
		{
			push(@Statement_Alpha,"$2\t$Sta_Alpha_Count");

			
		}
		
		$Sta_Alpha_Count++;
		
	}
	if($Statement=~m{\&lt;IOP_Roman\&gt\;}gsi)
	{
		my $Statement_Data=$Statement;
		my $Roman=uc(roman($Sta_Roman_Count));

		
		$Statement=~s{<statement([^\>]*)\>\n*<label>(\w+) (\d+)}{<statement$1><label>$2 $Roman}gsi;
		
		
		if($Statement_Data=~m{<statement content\-type=\"([^\"]+)\" id=\"([^\"]+)\">\n*<label>(\w+) (\d+)\.}gsi)
		{
			push(@Statement_Roman,"$2\t$Roman");
		}
		$Sta_Roman_Count++;

		
	}

	if($Statement=~m{\&lt;IOP_Alphabet ([A-Z])\&gt\;}gsi)
	{
		my $Alpha=$1;
		my $Statement_Data=$Statement;
		

		
		$Statement=~s{<statement([^\>]*)\>\n*<label>(\w+) (\d+)}{<statement$1><label>$2 $Alpha$3}gsi;
		if($Statement_Data=~m{<statement content\-type=\"([^\"]+)\" id=\"([^\"]+)\">\n*<label>(\w+) (\d+)\.}gsi)
		{
			push(@Statement_Alphabet,"$2\t$Alpha$4");
		}
		$Sta_Roman_Count++;

		
	}
	

	$Statement=~s{\&lt;IOP_Alpha\&gt\;}{}gsi;

	$Statement=~s{\&lt;IOP_Roman\&gt\;}{}gsi;

	$Statement=~s{\&lt;IOP_Alphabet ([A-Z])\&gt\;}{}gsi;

	

	my $List_Count=$Statement=~s{<list(\d?) }{<list$1 }gsi;

	
	
	if($List_Count eq "1")
	{
		
		$Statement=~s{<p content\-type=\"indent\"></p>}{}gsi;
		#$Statement=~s{<statement([^\>]*)\>\n*<label>([^\>]+)\<\/label>\n*(<list([^\>]+)\>(.*?)<\/list(\d+)>\n*)<\/statement>}{<statement$1><label>$2<\/label>\n<p>$3<\/p><\/statement>}gsi;
		#$Statement=~s{<statement([^\>]*)\>\n*<title>(.*?)<\/title>\n*(<list([^\>]+)\>(.*?)<\/list(\d+)>\n*)<\/statement>}{<statement$1><title>$2<\/title>\n<p>$3<\/p><\/statement>}gsi;

		
		
		$Statement=~s{(<list([^\>]+)\>(.*?)<\/list(\d+)>\n*)}{<p>$1<\/p>}gsi;

		$Statement=~s{(<list([^\>]+)\>(.*?)<\/list>\n*)}{<p>$1<\/p>}gsi;
	}

	$Statement=~s{<disp\-quote>(.*?)<\/disp\-quote>}{<p><disp\-quote>$1<\/disp\-quote><\/p>}gsi;

	
	
	
	
	return $Statement;
}

sub Num_Parts
{
	my $Num=shift;

	
	
	my $Label;

	if($Num=~m{<label>([^\<]+)<\/label><\/disp\-formula>}gsi)
	{
		
		$Label=$1;
		my $Label1=$1;
		$Label=~s{a\)$}{}gsi;
		$Label=~s{^\(}{}gsi;
		

		
		
		
	}

	my $Num1=$Num;

	while($Num1=~m{<label>\(((\d+)([b-z]))\)<\/label><\/disp\-formula>}gsi)
	{
		push(@Num_Parts,"$1\t$Label$3");
	}
			
	$Num=~s{<label>\((\d+)([b-z])\)<\/label><\/disp\-formula>}{<label>\($Label$2\)<\/label><\/disp\-formula>}gsi;

	

	
	
	return $Num;
}


