	$Glossary=~s{<glossaryTerm>(\s?)(.*?)([,:]?)(\s?)<\/glossaryTerm>(\s?)(\&\#x2013;)(\s?)<glossaryDefinition>(.*?)<\/glossaryDefinition>(\s?)([,:;]?)(\s?)}{<def-item><term>$2<\/term><x>$3$4$5$6$7<\/x><def><p>$8<\/p><\/def><\/def-item><x>$9$10$11<\/x>\n}gsi;

	$Glossary=~s{<glossaryTerm>(\s?)(.*?)([,:]?)(\s?)<\/glossaryTerm>(\s?)(\&ndash;)(\s?)<glossaryDefinition>(.*?)<\/glossaryDefinition>(\s?)([,:;]?)(\s?)}{<def-item><term>$2<\/term><x>$3$4$5$6$7<\/x><def><p>$8<\/p><\/def><\/def-item><x>$9$10$11<\/x>\n}gsi;

	if($Glossary!~m{<title>}gsi)
