sub Figure_Order
{
	my $Figure=shift;

	
	

	$Figure=~s{<fig}{<figure><fig}gsi;

	$Figure=~s{<fig id=\"F(\d\d)\"}{<fig id=\"F0$1\"}gsi;
	
	$Figure=~s{<fig id=\"F(\d)\"}{<fig id=\"F00$1\"}gsi;

	
	
	my @Fig_Array=split("<figure>",$Figure);

	my @Fig_sorted = sort { $a cmp $b } @Fig_Array;

	my $Final_Figure=join("",@Fig_sorted);

	

	$Final_Figure=~s{<fig id=\"F00}{<fig id=\"F}gsi;
	$Final_Figure=~s{<fig id=\"F0}{<fig id=\"F}gsi;

	
	
	return $Final_Figure;
}

