sub HTML_Table
{
	my $Table=shift;


	
	
	$Table=~s{<oasis:table([^\>]*)\>}{<table width="100%" border="1">}gsi;
	$Table=~s{<\/oasis:table>}{<\/table>}gsi;
	$Table=~s{<oasis:tgroup([^\>]*)\>}{<colgroup $1>}gsi;
