	#$Table=~s{<col align=\"([^\"]+)\" colname=\"([^\"]+)\" colnum=\"([^\"]+)\" colwidth=\"([^\"]+)\"\/>}{<col align=\"$1\" colname=\"$2\" colnum=\"$3\" colwidth=\"$4\"\/>}gsi;

	$Table=~s{<oasis:thead([^\>]*)\>}{<\/colgroup>\n<thead $1>}si;
	$Table=~s{<\/oasis:thead>}{<\/thead>}gsi;

	$Table=~s{<oasis:thead([^\>]*)\>}{<thead $1>}gsi;
	$Table=~s{<\/oasis:thead>}{<\/thead>}gsi;

	

	if($Table!~m{<thead}si)
	{
		
		$Table=~s{<oasis:tbody([^\>]*)\>}{<\/colgroup>\n<tbody>}gsi;
	}

	$Table=~s{<oasis:row([^\>]*)\>}{<tr>}gsi;
	$Table=~s{<\/oasis:row>}{<\/tr>}gsi;

	$Table=~s{(<col align=\"([^\"]+)\"\/>)(<col align=\"([^\"]+)\"\/>)}{$1\n$3\n}gsi;

	$Table=~s{<oasis:tbody([^\>]*)\>}{<tbody $1>}gsi;
	$Table=~s{<\/oasis:tbody>}{<\/tbody>}gsi;


	
	
	
	$Table=~s{(<thead([^\>]*)\>(.*?)<\/thead>)}{&Thead1($1)}gesi;

	$Table=~s{(<tbody([^\>]*)\>(.*?)<\/tbody>)}{&Tbody1($1)}gesi;

	

	$Table=~s{(<(th) ([^\>]*)\>)}{&HTML_Entry_Th($1,$2,$3)}gesi;

	$Table=~s{(<(td) ([^\>]*)\>)}{&HTML_Entry_Th($1,$2,$3)}gesi;

		
	#$Table=~s{<tr >}{<tr>}gsi;


	
	
	$Table=~s{<table ([^\>]+)\>\n*<colgroup ([^\>]+)\>\n*<thead}{<table $1>\n<colgroup $2\/>\n<thead}gsi;

	

	$Table=~s{(<col ([^\>]+)\>)\n*<thead}{$1\n<\/colgroup>\n<thead}gsi;

	
	$Table=~s{<th ([^\>]+)\><\?scolor_start (\w+)\?>(.*?)<\/th>}{<th $1><\?scolor_start $2\?>$3<\?scolor_end\?><\/th>}gsi;

	$Table=~s{<td ([^\>]+)\><\?scolor_start (\w+)\?>(.*?)<\/td>}{<td $1><\?scolor_start $2\?>$3<\?scolor_end\?><\/td>}gsi;
	
	return $Table;
}

