		$Reference=~s{<citation citation\-type=\"([^\"]+)\">(.*?)<\/citation>}{<element\-citation publication-type="$1">$2<\/element\-citation>}gsi;
		$Reference=~s{<name>(.*?)<\/name>}{<string\-name>$1<\/string\-name>}gsi;

		$Reference=~s{</surname><x>([^\<]+)\</x>}{<\/surname>}gsi;

		$Reference=~s{</given\-names><x>([^\<]+)\</x>}{<\/given\-names>}gsi;
		
		$Reference=~s{<x>([^\<]+)\</x>}{}gsi;


		$Reference=~s{</fpage>\&\#x2013\;<lpage>}{</fpage><lpage>}gsi;

		$Reference=~s{<year>\((\w+)\)<\/year>}{<year>$1<\/year>}gsi;

		$Reference=~s{<uri xlink:href=\"(https://doi([^\>]+))\>(.*?)<\/uri>}{<pub-id pub-id-type=\"doi\" assigning-authority=\"crossref\" xlink:href=\"$1>$3<\/pub\-id>}gsi;

		
	
	return $Reference;
}

sub HTML_Entry_Th
{
	my $Entry=shift;

	

	my $Tag=shift;
	
	my $Att=shift;

	

	my $Att1=$Att;

	my $Att2=$Att;

	my $Att3=$Att;

	my $align;
	my $colspan="";
	my $rowspan="";
	my $column="";

	my $Background_Color="";
	
	
	if($Att=~m{align=\"([^\"]+)\"}si)
	{
		$align=$1;
	}
	if($Att=~m{colname=\"col([^\"]+)\"}si)
	{
		$column=$1;
	}
	
	if($Att=~m{namest=\"(col?)(\d+)\" nameend=\"(col?)(\d+)\"}si)
	{
		my $Start=$2;
		my $End=$4;
		$colspan=$End-$Start+1;

		
	}
	if($Att=~m{morerows=\"([^\"]+)\"}si)
	{
		$rowspan=$1+1;
	}

	if($Att=~m{rowspan=\"([^\"]+)\"}si)
	{
		$rowspan=$1;
	}

	
	if($Att1=~m{colspan=\"([^\"]+)\"}si)
	{
		$colspan=$1;
	}

	
	if($Att2=~m{style=\"background\:\&num;(\w+)}si)
	{
		$Background_Color=$1;
	}

	if($Att3=~m{ background\-color\: rgb\((\d+), (\d+)\, (\d+)\)}si)
	{
		$Background_Color = rgb_to_hex($1, $2, $3);

		$Background_Color=~s{\#}{}gsi;

		
	}

	
	$Entry=~s{<entry ([^\>]+)\>}{}gsi;
	my $A="align=\"$align\" colname=\"col$column\" colspan=\"$colspan\" rowspan=\"$rowspan\"";
	$A=~s{colspan=\"\"}{}gsi;
	$A=~s{rowspan=\"\"}{}gsi;
	$A=~s{align=\"\"}{}gsi;
	$A=~s{column=\"\"}{}gsi;
	$A=~s{\s{1,}}{ }gsi;
	$A=~s{ $}{}gsi;
	
	$Entry="<$Tag $A><\?scolor_start $Background_Color\?>";

	

	$Entry=~s{<th >}{<th>}gsi;
	$Entry=~s{<td >}{<td>}gsi;

	$Entry=~s{<\?scolor_start \?>}{}gsi;
	
	#if($Att=~m{aid5:cellstyle=\"TabCH\"}gsi)
	#{
	#$Entry=~s{(<entry([^\>]*)\>(.*?)<\/entry>)}{<thead>$1<\/thead>}gsi;
	#$Entry=~s{<entry ([^\>]*)\>(.*?)<\/entry>}{<th $1>$2<\/th>}gsi;
	#}
	
	#if($Att=~m{aid5:cellstyle=\"Tabbody}gsi)
	#{
	#$Entry=~s{(<entry([^\>]*)\>(.*?)<\/entry>)}{<tbody>$1<\/tbody>}gsi;
	#$Entry=~s{<entry ([^\>]*)\>(.*?)<\/entry>}{<td $1>$2<\/td>}gsi;
	#}
	$Entry=~s{\n{1,}}{\n}gsi;

	
	
	
	
	return $Entry;
}


sub OUP_Table_Alignment
{
	my $Table=shift;

	

	if($Table=~m{<\!--\[TableAlignment ([^\]]+)\]}gsi)
	{
		my $Alignment=$1;

		my @Align=split(";",$Alignment);

		foreach my $Value(@Align)
		{
			
			if($Value=~m{col(\d+)\:(.*)$}gsi)
			{
				my $Col=$1;
				my $Attribute=$2;
				$Attribute=~s{\'}{\"}gsi;
				$Attribute=~s{valign}{char}gsi;
				$Attribute=~s{ char=\"\"}{}gsi;
				$Attribute=~s{align=\'\'}{}gsi;
				$Attribute=~s{ char=\'\'}{}gsi;
				$Attribute=~s{align=\"\"}{}gsi;
				$Attribute=~s{align=\"0\"}{align=\"left"}gsi;
				$Attribute=~s{align=\"1\"}{align=\"right"}gsi;
				$Attribute=~s{align=\"2\"}{align=\"center"}gsi;
				$Attribute=~s{align=\"3\"}{align=\"justify"}gsi;
				
				$Attribute=~s{char=\"0\"}{char=\",\"}gsi;
				$Attribute=~s{char=\"1\"}{char=\"\.\"}gsi;
				$Attribute=~s{char=\"2\"}{char=\"\(\"}gsi;
				$Attribute=~s{char=\"3\"}{char=\"\:\"}gsi;
				$Attribute=~s{char=\"4\"}{char=\"\+\"}gsi;
				$Attribute=~s{char=\"5\"}{char=\"\\\"}gsi;
				$Attribute=~s{char=\"6\"}{char=\"\%\"}gsi;
				$Attribute=~s{char=\"7\"}{char=\"unit\"}gsi;
				$Attribute=~s{char=\"8\"}{char=\"plusmn\"}gsi;
				$Attribute=~s{char=\"9\"}{char=\"hyphen\"}gsi;
				$Attribute=~s{char=\"10\"}{char=\"ndash\"}gsi;
				$Attribute=~s{char=\"11\"}{char=\"mixed\"}gsi;
				$Attribute=~s{char=\"12\"}{char=\"text\"}gsi;
				$Attribute=~s{char=\"13\"}{char=\"\/\"}gsi;

				
				
		#$Table=~s{<oasis\:colspec align=\"([^\"]+)\" (colname=\"col$Col\" ([^\>]*)\>)}{<oasis:colspec $Attribute $2}si;


				
			
		$Table=~s{(<oasis\:entry colname=\"col$Col\"([^\>]*)\>)}{$1\<\?$Attribute\?\>}si;

		

		$Table=~s{<\?align=\"([^\"]+)\" char=\"([^\"]+)\"\?>}{<\?align $1\?><\?char $2\?>}gsi;

		
		$Table=~s{<\?align=\"([^\"]+)\"\?>}{<\?align $1\?>}gsi;

		$Table=~s{<\?char=\"([^\"]+)\"\?>}{<\?char $1\?>}gsi;

		$Table=~s{<\? char=\"([^\"]+)\"\?>}{<\?char $1\?>}gsi;
		
				}
		}
	}

	$Table=~s{<\?\?>}{}gsi;
	
	$Table=~s{<\!--\[TableAlignment ([^\]]+)\]\-\->}{}gsi;
	return $Table;
}

