sub AUP_Reference
{
	my $Reference=shift;

	$Reference=~s{<ref ([^\>]+)\>}{\[ref $1\]}gsi;

	$Reference=~s{<citation ([^\>]+)\>}{<citation>}gsi;

	$Reference=~s{<(ref|citation|italic|bold|sup|sub|sc)>}{\[$1\]}gsi;

	$Reference=~s{<\/(ref|citation|italic|bold|sup|sub|sc)>}{\[\/$1\]}gsi;

	#$Reference=~s{<\w([^\>]*)>}{}gsi;

	#$Reference=~s{<\/\w([^\>]*)>}{}gsi;

	$Reference=~s{\[ref ([^\]]+)\]}{<ref $1>}gsi;

	$Reference=~s{\[(ref|citation|italic|bold|sup|sub|sc)\]}{<$1>}gsi;

