sub IOP_Ack
{
	my $Ack=shift;

	

	$Ack=~s{<title>\&lt\;ack_Head([A])\&gt;(.*?)\&lt\;\/ack_Head([A])\&gt;<\/title>}{<sec1>\n<title>$2<\/title>}gsi;
	$Ack=~s{<title>\&lt\;ack_Head([B])\&gt;(.*?)\&lt\;\/ack_Head([B])\&gt;<\/title>}{<sec2>\n<title>$2<\/title>}gsi;
	$Ack=~s{<title>\&lt\;ack_Head([C])\&gt;(.*?)\&lt\;\/ack_Head([C])\&gt;<\/title>}{<sec3>\n<title>$2<\/title>}gsi;

	
	
$Ack=~s{<\/ack>}{\n<sec1><empty><\/ack>}si;



my @body;
my ($lvl,$prevlvl);
$lvl = $prevlvl = 0;
 
@body = split ('\n', $Ack);


foreach my $line (@body)
{
	
	
	if($line =~ /<sec([0-9])>/)
	{
                $lvl=ord($1);
		
                my $closetag = '';
                for(my $i=$prevlvl;$i>=$lvl;$i--)
                {
                        my $l = chr($i);
			
                        $closetag = $closetag . "\n</sec$l>";
			
                }
                $line = $closetag . "\n" . $line;
                $prevlvl = $lvl;
        }
}

my $lines =join("\n",@body);
$Ack=$lines;



$Ack=~s{<sec(\d+)><empty>}{}gsi;






my $Asec="1";

$Ack=~s/<sec(\d+)>/'<sec id="as'.$Asec++.'">'/segi;

$Ack=~s{<\/sec(\d+)>}{<\/sec>}gsi;

my $Ack1=$Ack;



if($Ack1=~m{<sec}gsi)
{  
$Ack=~s{<\/ack>}{}gsi;
}
$Ack=~s{<sec}{<\/ack>\n<sec}si;

	return $Ack;
}


