sub StatementLevel
{
        my $secCont=shift;
        $secCont=~s#\n+#\n#gsi;
        $secCont=~s#\n#<enter>#gsi;
        $secCont=~s#<#\n<#gsi;
        $secCont=~s#>#>\n#gsi;
        my @Array=split("\n",$secCont);

        my $num='1';
        for (my $i=0; $i<scalar(@Array); $i++)
        {
                if ($Array[$i]=~m#<statement>#si)
                {
                    $Array[$i]=~s#<statement>#<statement$num>#si;
                    $num++;
                }
                if ($Array[$i]=~m#</statement>#si)
                {
                    $num--;
                    $Array[$i]=~s#</statement>#</statement$num>#si;
                }
        }

        $secCont=join("",@Array);
        $secCont=~s#<enter>#\n#gsi;
        return $secCont;
}

