sub LWW_Ack
{
	my $Ack=shift;

	
	my $Ack1=$Ack;

	$Ack1=~s{<([^\>]+)\>}{}gsi;

	

	if($Ack1=~m{Affiliation}gsi)
	{
		$Ack=~s{<ackhead>(.*?)<\/ackhead>}{<ack content-type=\"Affiliation\"><title>$1<\/title><p><\/p><\/ack>}gsi;
	}
	if($Ack1=~m{(Footnote|ARTICLE INFORMATION)}gsi)
	{
		$Ack=~s{<ack>}{<ack content-type="Footnote">}gsi;

		$Ack=~s{<ackhead>(.*?)<\/ackhead>}{<ack content-type=\"Footnote\"><title>$1<\/title><p><\/p><\/ack>}gsi;
	}
	if($Ack1=~m{(Correspondence)}gsi)
	{
		$Ack=~s{<ack>}{<ack content-type="Corresp">}gsi;

		$Ack=~s{<ackhead>(.*?)<\/ackhead>}{<ack content-type=\"Corresp\"><title>$1<\/title><p><\/p><\/ack>}gsi;
	}
	if($Ack1=~m{(Sources of funding)}gsi)
	{
		#$Ack=~s{<ack>}{<ack content-type="funding">}gsi;

		#$Ack=~s{<ackhead>(.*?)<\/ackhead>}{<ack content-type=\"funding\"><title>$1<\/title>}gsi;
	}
	if($Ack1=~m{(Sources of)}gsi)
	{
		$Ack=~s{<ack>}{<ack content-type="funding">}gsi;

		$Ack=~s{<ackhead>(.*?)<\/ackhead>}{<ack content-type=\"funding\"><title>$1<\/title>}gsi;
	}
	if($Ack1=~m{Footnote}gsi)
	{
		
		
	}
	if($Ack1=~m{Affiliation}gsi)
	{
		
		#$Ack=~s{<ackhead>(.*?)<\/ackhead>}{<ack content-type=\"Affiliation\"><title>$1<\/title><p><\/p><\/ack>}gsi;
	}
	
	return $Ack;
}

sub asciiize {
    return $_[0] if (ord($_[0]) < 128);     
    return sprintf('&#x%04X;', ord($_[0])); 
}

