		if($Tmp=~m{<contrib$Contrib_No ([^\>]+)\>(.*?)<\/contrib>}gsi)
		{
			push(@Contrib,"<contrib $1>$2<\/contrib>");
		}
	}

	my $Final_Contrib=join("\n",@Contrib);

	my @email;

	while($Final_Contrib=~m{<email>(.*?)<\/email>}gsi)
	{
		push(@email,"<ext-link ext-link-type=\"email\">$1</ext-link>");
	}

	$Final_Contrib=~s{\(<email>(.*?)<\/email>\)}{}gsi;
	
	$Final_Contrib=~s{<email>(.*?)<\/email>}{}gsi;

	$Final_Contrib=~s{<x>([^\<]+)\<\/x>}{}gsi;

	$Final_Contrib=~s{ and<\/contrib>}{<\/contrib>}gsi;
	
	my $Final_Email=join("\n",@email);

	$Article=~s{</front-stub>}{<contrib\-group>\n$Final_Contrib\n$Final_Email\n<\/contrib\-group>\n<\/front\-stub>}gsi;

	

	return $Article;
}

sub IOP_PED_Review
{
	my $Reference=shift;

	my $Ref_Tmp=$Reference;

	
	
	while($Ref_Tmp=~m{<ref id=\"([^\"]+)\"><(\w+)\>}gsi)
