		$Reference=~s{<xref ref\-type=\"bibr\" rid=\"$R2\">}{<xref1 ref\-type=\"bibr\" rid=\"$R1\">}gsi;

		
		
	}

	$Reference=~s{<xref1}{<xref}gsi;

	#$Reference=~s{<ref id=\"([^\"]+)\"><(\w+)\>}{<ref id=\"$1\">}gsi;
	
	return $Reference;
}

