	$Footnote=~s{<fn fn\-type=\"fn\"><p>\&lt\;\/foot_disp\&gt\;</p></fn>}{<\/EquationDisplay>}gsi;

	$Footnote=~s{\n*\&lt\;List_Disp\&gt\;\n*}{}gsi;

	$Footnote=~s{\n*\&lt\;\/List_Disp\&gt\;\n*}{}gsi;

	$Footnote=~s{\n*\&lt\;\/Num_Parts\&gt\;\n*}{}gsi;
	$Footnote=~s{\n*\&lt\;Num_Parts\&gt\;\n*}{}gsi;

	$Footnote=~s{<fn fn\-type=\"fn\"><p></p></fn>}{}gsi;
	
	$Footnote=~s{<EquationDisplay>\n*<fn fn\-type=\"fn\"><p>(.*?)<\/p><\/fn>\n*<\/EquationDisplay>}{<EquationDisplay>$1<\/EquationDisplay>}gsi;

	$Footnote=~s{<fn fn\-type=\"fn\"><p></p></fn>}{}gsi;

	$Footnote=~s{<fn fn\-type=\"fn\"><p>}{}gsi;

	$Footnote=~s{<\/p><\/fn>}{}gsi;

