sub Maths_Key
{

	my $Maths=shift;

	$Maths=~s{<kwd><\/kwd><x> </x>}{<x> <\/x>}gsi;

	$Maths=~s{<x><\/x>\n*<x> <\/x>}{<x> <\/x>}gsi;

	$Maths=~s{<kwd>(.*?)<\/kwd>}{&Keyword_Split($1)}gesi;
	
	return $Maths;
}

sub Keyword_Split
{
	my $Kwd=shift;

	my @Key=split("\, ",$Kwd);

	my @K;
	foreach my $Value(@Key)
	{
		push(@K,"<kwd>$Value</kwd>");
	}

	my $Final_K=join("<x>, </x>\n",@K);
		    
	
	return $Final_K;
}

