sub Figure_Label
{
	my $Figure=shift;

	
	
	my $Start=shift;

	my $End=shift;

	my @Array_Id;

	
	for(my $i=$Start;$i<=$End;$i++)
	{
		push(@Array_Id,"F$i");
	}
				
	my $Final_Id=join(" ",@Array_Id);

	

	$Figure=~s{<fig id=\"([^\"]+)\"}{<fig id=\"$Final_Id\"}gsi;

	
	
	return $Figure;
}

