	if($Orcid1=~m{<contrib\-id contrib\-id\-type=\"orcid\">(.*?)<\/contrib\-id>}gsi)
	{
		my $OID=$1;

		
				
		$Orcid=~s{<x>([^\<]+)\<\/x><\/contrib>}{<xref ref-type=\"orcid\" xlink:href=\"$OID\"\/><x>$1<\/x><\/contrib>}gsi;
