		$Orcid=~s{(<x>([^\<]+)\<\/x><xref ([^\>]+)\><xref ([^\>]+)\>)<\/contrib>}{<xref ref-type=\"orcid\" xlink:href=\"$OID\"\/>$1<\/contribs>}gsi;
				
		$Orcid=~s{<xref ([^\>]+)\></contrib>}{<xref $1><xref ref-type=\"orcid\" xlink:href=\"$OID\"\/><\/contrib>}gsi;
				
		$Orcid=~s{</xref></contrib>}{<\/xref><xref ref-type=\"orcid\" xlink:href=\"$OID\"\/><\/contrib>}si;

		$Orcid=~s{</name></contrib>}{<\/name><xref ref-type=\"orcid\" xlink:href=\"$OID\"\/><\/contrib>}si;

		

		$Orcid=~s{<contrib\-id contrib\-id\-type=\"orcid\">(.*?)<\/contrib\-id>}{}gsi;

		
		
				
	}

	my $Orcid3=$Orcid;

	if($Orcid2=~m{<contrib\-id contrib\-id\-type=\"orcid\">(.*?)<\/contrib\-id>}gsi)
	{
		my $ID=$1;

		
		if($Orcid3=~m{<xref ref\-type=\"orcid\"([^\>]+)\>(.*?)<\/xref>}gsi)
