sub Grand_No
{
	my $Grand=shift;

	
	
	my $Grand1=$Grand;
	my $Grand2=$Grand;

	my $Funder_Name;
	my $Funder_ID;
	my @Award_ID;

	
	
	if($Grand=~m{<grant\-sponsor id=\"([^\"]+)\">}gsi)
	{
		$Funder_ID=$1;
		$Funder_ID=~s{(\s)$}{}gsi;
	}

	if($Grand1=~m{<grant\-sponsor([^\>]*)\>(.*?)<\/grant\-sponsor>}gsi)
	{
		$Funder_Name=$2;
	}

	while($Grand2=~m{<grant\-num\>(.*?)<\/grant\-num>}gsi)
	{
		push(@Award_ID,"<award-id>$1<\/award-id>");
	}

	$Funder_Name=~s{<italic>(.*?)<\/italic>}{$1}gsi;
	$Funder_Name=~s{<bold>(.*?)<\/bold>}{$1}gsi;
	

	my $Final_Award_Id=join("\n",@Award_ID);

	$Grand="<award-group award-type=\"grant\">\n<funding-source>\n<institution-wrap>\n<institution>$Funder_Name</institution>\n<institution-id institution-id-type=\"DOI\">10.13039/$Funder_ID</institution-id></institution-wrap><\?release-delay 12|0\?></funding-source>\n$Final_Award_Id\n</award-group>";


	
	$Grand=~s{<named\-content content\-type=\"funder\-identifier\">10\.13039\/</named\-content>}{}gsi;

	$Grand=~s{<institution\-id institution\-id\-type=\"DOI\">10.13039\/</institution\-id>}{}gsi;

	push(@OUP_Funding,"$Grand");
	
	return $Grand;
}

