		if($Tmp=~m{<corresp id=\"c$Contrib_Count\">}gsi)
		{
		
		
		$Contrib=~s{<contrib contrib\-type=\"author\" corresp=\"yes\">(.*?)<\/contrib>}{"<contrib contrib\-type=\"author\" corresp=\"yes\">$1<xref ref-type=\"corresp\" rid=\"c".$Contrib_Count++."\"/><\/contrib>"}gesi;

		}

		else
		{
			$Contrib=~s{<contrib contrib\-type=\"author\" corresp=\"yes\">(.*?)<\/contrib>}{<contrib contrib\-type=\"author\" corresp=\"yes\">$1<xref ref-type=\"corresp\" rid=\"c1\"/><\/contrib>}gsi;
		}
	}
	
	return $Contrib;
}

sub AUP_Unnumbered_Figure
{
	my $Figure=shift;

	

	$Figure=~s{<fig>(.*?)<\/fig>}{"<fig id=\"UF$Unfig\" position=\"anchor\" fig\-type=\"figure\">$1<graphic xlink\:href=\"$FileName\_UF".$Unfig++."\.eps\"\/><\/fig>"}egsi;

	$Figure=~s{<fig id=\"UF0}{<fig id=\"UF}gsi;

	
	
	
	
	return $Figure;
}

sub Contrib_Notes
{
	my $Contrib=shift;

	$Contrib=~s{<x>}{<x1>}gsi;
	$Contrib=~s{<\/x>}{<\/x1>}gsi;
	
	return $Contrib;
}

sub Sec_Back
{
	my $Sec=shift;

	$Sec=~s{<ack([^\>]*)\>}{}gsi;

	$Sec=~s{<\/ack>}{}gsi;
	
	return $Sec;
}

sub Ref_Article_Query
{
	my $Ref=shift;

	my $Ref_Id=shift;

	$Ref_Id=~s{CIT(0*)}{}gsi;

	my $Ref1=$Ref;

	if($Ref1=~m{<citation citation\-type=\"journal\">(.*?)<\/citation>}gsi)
	{
		my $Art_Title=$1;

		if($Art_Title!~m{<article\-title>(.*?)<\/article\-title>}gsi)
		{
			$Ref=~s{<\/citation>}{<\!\-\-\[AQ: Reference \[$Ref_Id\] in this journal should include article titles; please provide a list of titles along with your proof corrections.\]\-\-><\/citation>}gsi;
		}

		else
		{
			$Ref_Query_Count="1";
		}
	}
	
	return $Ref;
}

sub Ref_Article_Query1
{
	my $Ref=shift;

	my $Ref_Id=shift;

	$Ref_Id=~s{CIT(0*)}{}gsi;

	my $Ref1=$Ref;

	if($Ref1=~m{<citation citation\-type=\"journal\">(.*?)<\/citation>}gsi)
	{
		my $Art_Title=$1;

		my $Author=$1;

		my $Name;
		my $Year;
		if($Author=~m{<surname>(.*?)<\/surname>}gsi)
		{
			$Name=$1;
		}
		if($Author=~m{<year>(.*?)<\/year>}gsi)
		{
			$Year=$1;
		}

		my $Author1=$Author;

		my $Count=$Author1=~s{<name>}{<name>}gsi;

		if($Count gt 1)
		{
			$Name="$Name et al.";
		}
		
		if($Art_Title!~m{<article\-title>(.*?)<\/article\-title>}gsi)
		{
			$Ref=~s{<\/citation>}{<\!\-\-\[AQ: Please provide the article title for \[$Name $Year].\]\-\-><\/citation>}gsi;
		}

		
	}
	
	return $Ref;
}

sub Fn_Text
{
	my $Text=shift;

	$Text=~s{<fn id=\"([^\"]+)\" fn\-type=\"fntext\">(<p>(.*?)Editor\:(\s?)(.*?)<\/p><\/fn>)}{<fn id=\"$1\" fn\-type=\"guesteditor\">$2<GuestEditor><contrib contrib-type="author" corresp="no">$5<\/contrib><\/GuestEditor>}gsi;

	
	return $Text;
}

sub Def_Figure
{
	my $Def=shift;

	$Def=~s{<\/p>\n(<fig ([^\>]+)\>(.*?)<\/fig>)\n*<\/def>}{$1<\/p>\n<\/def>}gsi;
	
	return $Def;
}

sub IOP_Chinese_Author
{
	my $Author=shift;

	my $Author1=$Author;

	$Author1=~s{\&\#(\w+);}{}gsi;

	$Author1=~s{\&(\w+);}{}gsi;

	$Author1=~s{<([^\<]+)\>}{}gsi;

	if($Author1!~m{(\w)}gsi)
	{
		$Author=~s{<name>(.*?)<\/name>}{<name name\-style=\"eastern\">$1<\/name>}gsi;

		$Author=~s{<surname>(.*?)<\/surname>}{<surname><entity font=\"SimSun\">$1<\/entity><\/surname>}gsi;

		$Author=~s{<given\-names>(.*?)<\/given\-names>}{<given\-names><entity font=\"SimSun\">$1<\/entity><\/given\-names>}gsi;

		
		
	}
	
	return $Author;
}


sub Key_Digital_Content
{
	my $Tmp=shift;

	my $Final_Affiliation=shift;

	my ($Subject,@Authors,@Affiliation,$Group,@Funder,@Orcid,$Article_Title,@Keys,@Collection,@Related_Articles);

	my $Subject_Tmp=$Tmp;

	if($Tmp=~m{<subj\-group subj\-group\-type=\"category\-toc\-heading\">\n<subject>(.*?)<\/subject>}gsi)
	{
		$Subject=$1;
	}

	my $Author_Tmp=$Tmp;

	my @Aut;

	while($Author_Tmp=~m{<contrib contrib\-type=\"author\" corresp=\"([^\"]+)\">(.*?)<\/name>}gsi)
	{
		my $Author=$2;

		

		$Author=~s{<name>\s*(<surname>([^\<]+)\<\/surname>)(<x>([^\<]*)\<\/x>)(<given\-names>([^\<]+)\<\/given\-names>)}{<name>$5$3$1}gsi;
		
		$Author=~s{<([^\>]+)\>}{}gsi;

		$Author=~s{\n}{}gsi;
		

		push(@Aut,$Author);
	}
	
	my $Final_Author=join(", ",@Aut);

	if($Final_Author eq "")
	{
		$Final_Author="NA";
	}

	$Final_Author=~s{\,\,}{\,}gsi;
	
	my $Aff_Tmp=$Tmp;

	my @Affiliation;
	
	while($Aff_Tmp=~m{<aff ([^\>]+)\>(.*?)<\/aff>}gsi)
	{
		my $Aff=$2;

		$Aff=~s{^<sup>([^\<]+)\<\/sup>}{$1 }si;

		$Aff=~s{<([^\>]+)\>}{}gsi;

		push(@Affiliation,$Aff);
	}

	my $Final_Aff=join("\n<break/>",@Affiliation);

	if($Final_Aff eq "")
	{
		$Final_Aff="NA";
	}

	my $Corres_Tmp=$Tmp;

	my @Corres;
	
	while($Corres_Tmp=~m{<corresp ([^\>]+)\>(.*?)<\/corresp>}gsi)
	{
		my $Cor=$2;
		
		$Cor=~s{<([^\>]+)\>}{}gsi;

		push(@Corres,$Cor);
		
	}

	my $Final_Cor=join("\n<break/>",@Corres);

	if($Final_Cor eq "")
	{
		$Final_Cor="NA";
	}

	my $Funder_Tmp=$Tmp;

	my @Funder;
	while($Funder_Tmp=~m{<named\-content content\-type=\"funder\-name\">(.*?)<\/named\-content>}gsi)
	{
		push(@Funder,$1);
	}

	my $Final_Funder=join("\n<break/>",@Funder);

	if($Final_Funder eq "")
	{
		$Final_Funder="NA";
	}

	my $Orcid_Tmp=$Tmp;

	my @Orcid;

	while($Orcid_Tmp=~m{<xref ref\-type=\"orcid\" xlink\:href=\"([^\"]+)\"}gsi)
	{
		push(@Orcid,$1);
	}

	my $Final_Orcid=join("\n<break/>",@Orcid);

	if($Final_Orcid eq "")
	{
		$Final_Orcid="NA";
	}

	my $Article_Tmp=$Tmp;

	if($Article_Tmp=~m{<title\-group>\n<article\-title>(.*?)<\/article\-title>}gsi)
	{
		$Article_Title=$1;
	}

	if($Article_Title eq "")
	{
		$Article_Title="NA";
	}

	my $Key_Tmp=$Tmp;
	my $Key;

	if($Key_Tmp=~m{<kwd\-group>(.*?)<\/kwd\-group>}gsi)
	{
		$Key=$1;

		$Key=~s{<title>(.*?)<\/title>(\s?)}{}gsi;

		$Key=~s{\n}{}gsi;
		
		$Key=~s{<([^\>]+)\>}{}gsi;

		
	}

	if($Key eq "")
	{
		$Key="NA";
	}

my $Note_Tmp=$Tmp;

my @Notes;

if($Note_Tmp=~m{<notes ([^\>]+)\>(.*?)<\/notes>}gsi)
{
	my $Note=$2;

	while($Note=~m{<contrib ([^\>]+)\>(.*?)<\/contrib>}gsi)
	{
		my $Author=$2;
		
		$Author=~s{<name>\s*(<surname>([^\<]+)\<\/surname>)(<x>([^\<]*)\<\/x>)(<given\-names>([^\<]+)\<\/given\-names>)}{<name>$5$3$1}gsi;
		
		$Author=~s{<([^\>]+)\>}{}gsi;

		$Author=~s{\n}{}gsi;

		push(@Notes,$Author);
	}
}

my $Final_Collab_Author=join(", ",@Notes);

if($Final_Collab_Author eq "")
	{
		$Final_Collab_Author="NA";
	}

my $Source_Dir=$ARGV[0];
$Source_Dir=~s{\\Word(.*)}{\\From_Client}si;
$Source_Dir=~s{\\Editorial(.*)$}{\\From_Client}si;
$Source_Dir=~s{\\For\-CE(.*)}{\\From_Client}si;




my @files;


opendir DIR,$Source_Dir or die "can't read '$Source_Dir' $!\n";
@files = map{ "$_" }grep{ /(\.xml)$/i }readdir( DIR );
closedir DIR;	

my ($Cats_File,$Cats);

if(scalar(@files) ge "1")
{
$Cats_File=$Source_Dir."\\$files[0]";

}

open(THN,$Cats_File) || die "Can't open file '$Cats_File': $!\n";
{ local $/; $_=<THN>; $Cats=$_; }
close(THN);




$Cats=~s{ {1,}}{ }gsi;
$Cats=~s{\n\s}{\n}gsi;

my $Cats1=$Cats;
my $Cats2=$Cats;


my $Subj_Category;

if($Cats=~m{<SubjectSectionCode>(.*?)<\/SubjectSectionCode>}gsi)
	{
		 $Subj_Category=$1;
	}

if($Subj_Category eq "")
{
		$Subj_Category="NA";
}	



my @Subject_Class;
while($Cats1=~m{<subj\-group subj\-group\-type=\"Classification\">(.*?)<\/subj\-group>}gsi)
{
	my $Subj_Group=$1;
	

	while($Subj_Group=~m{<subject>(.*?)<\/subject>}gsi)
	{
		my $Sub=$1;
		
		push(@Subject_Class,$Sub);
		}
}




my $Final_Subject=join(", ",@Subject_Class);

if($Final_Subject eq "")
{
		$Final_Subject="NA";
}	

my @Link;
if($Cats2=~m{<LinkedManuscripts HasLinkedManuscripts=\"true\">(.*?)<\/LinkedManuscripts>}si)
{
	my $Doi_Link=$1;

	
	my $Count=1;
	while($Doi_Link=~m{<LinkedDoi>(.*?)<\/LinkedDoi>}gsi)
	{
		push(@Link,$1);
		
	}

}

my $Final_Linked=join(", ",@Link);

if($Final_Linked eq "")
{
		$Final_Linked="NA";
}	

my @Suppl;

my $DestinationDirectory = dirname($ARGV[0]);

$DestinationDirectory=~s{\\Word(.*?)$}{\\From_Client\\Accepted_manuscripts}gsi;
$DestinationDirectory=~s{\\Editorial(.*?)$}{\\From_Client\\Accepted_manuscripts}gsi;
$DestinationDirectory=~s{\\For\-CE(.*?)$}{\\From_Client\\Accepted_manuscripts}gsi;

if(-e "$DestinationDirectory")
{

my @files;	
opendir DIR,$DestinationDirectory or die "can't read '$DestinationDirectory' $!\n";
find(
   sub {
push(@files,$File::Find::name)if /([^_])(.*)$/},$DestinationDirectory);
closedir DIR;



@files=sort(@files);
foreach my $File_Name(@files)
{
	
	if($File_Name=~m{Suppl\_data\/(\w.*)$}gsi)
	{
	
	push(@Suppl,$1);

	}
	
}

}

my $Final_Suppl=join("\n",@Suppl);


my $Table=<<EOT;
<sec>
<title/>
<table-wrap position="background">
<caption><p><bold>Action: check your manuscript information</bold></p><p>Please check that the information in the table is correct. We use this information in the online version of your article and for sharing with third party indexing sites, where applicable.</p></caption>
<tables width="100%" border="1">
<colgroup cols="2" colstubs=".97">
<col align="left" colname="col1" colnum="1" colwidth="50.00%"/>
<col align="left" colname="col1" colnum="1" colwidth="50.00%"/>
</colgroup>
<tbody valign="top">
<tr>
<td colname="col1"><p><?double double?><bold>Full affiliations</bold><break/>
Each unique affiliation should be listed separately; affiliations must contain only the applicable department, institution, city, territory, and country<?align left?> <?char text?></p></td>
<td colname="col2"><p>$Final_Affiliation<?align left?> <?char text?></p></td>
</tr>
<tr>
<td colname="col1"><p><bold>Group Contributors</bold><break/>
The name of the group and individuals in this group should be given, if applicable (e.g. The BFG Working Group: Simon Mason, Jane Bloggs)</p></td>
 <td colname="col2"><p>$Final_Collab_Author</p></td>
</tr>
<tr>
<td colname="col1"><p><bold>Supplementary data files cited</bold></p></td>
<td colname="col2"><p>$Final_Suppl</p></td>
</tr>
<tr>
<td colname="col1"><p><bold>Funder Name(s)</bold><break/>
Please give the full name of the main funding body/agency. This should be the full name of the funding body without abbreviation or translation, if unsure, see <uri xlink:href="https://search.crossref.org/funding">https://search.crossref.org/funding</uri></p></td>
<td colname="col2"><p>$Final_Funder</p></td>
</tr>
</tbody>
</tables>
</table-wrap>
</sec>
EOT



$Tmp=~s{<\/body>}{$Table<\/body>}gsi;

return $Tmp;
}

sub Aff_Institution
{
	my $Aff=shift;

	my $Aff1=$Aff;
	
	my $Aff2=$Aff;


	my $Aff_Comma_Count=$Aff=~s{\,}{\,}gsi;

	#if($Aff1!~m{\,(.*?)\,(.*?)}gsi)
	#{

		if($Aff2=~m{(Institute|University|Center|Centre|Hospital|Organization|Limited|Foundation|)}gsi)
		{

			if($Aff_Comma_Count eq 1)
			{
			$Aff=~s{<institution>(.*?)\,(.*?)<\/institution>}{<institution>$1\,<\/institution><university>$2<\/university>}gsi;
			}

			if($Aff_Comma_Count eq 2)
			{
			$Aff=~s{<institution>(.*?)\,(.*?)\,(.*?)<\/institution>}{<institution>$1\,$2<\/institution><university>$3<\/university>}gsi;
			}
			
		}
	#}

	$Aff=~s{<university>(\s?)and(\s?)</university>}{$1and$2}gsi;

	$Aff=~s{<\/institution><university>(\s?)}{$1<\/institution><university>}gsi;

	
	
	return $Aff;
}

