sub Crocol_Abstract
{
	my $Abstract=shift;

	my $Text=shift;

	$Text=~s{<\!\-\-(.*?)\-\->}{}gsi;

	$Text=~s{<p>(.*?)<\/p>}{$1}gsi;

	

	$Text=~s{\n}{}gsi;

	

	$Abstract=~s{<\!\-\-(.*?)\]\-\->}{<\!\-\-$1 $Text\]\-\->}gsi;
	
	return $Abstract;
}

sub JBREIM_Abstract
{
	my $Abstract=shift;

	$Abstract=~s{\:(\s?)<\/title>}{<x content\-type=\"onlyforpdf\">\:<\/x><\/title>$1}gsi;
	
	return $Abstract;
}

sub Key_Table
{
	my $Key=shift;

	
	
	$Key=~s{<table }{<tables }gsi;
	$Key=~s{<\/table>}{<\/tables>}gsi;

	$Key=~s{<oasis\:entry ([^\>]+)\>}{<td $1><p>}gsi;
	$Key=~s{<\/oasis\:entry>}{<\/p><\/td>}gsi;
	
	$Key=~s{<\?([^\>]+)\>}{}gsi;

	$Key=~s{<td ([^\>]+)\><p>}{<td $1><p><\?double double\?>}si;

	$Key=~s{<td colname=\"col1\"><p>(.*?)<\/p>}{<td colname=\"col1\"><p>$1<\?align left\?> <\?char text\?></p>}si;
	$Key=~s{<td colname=\"col2\"><p>(.*?)<\/p>}{<td colname=\"col2\"><p>$1<\?align left\?> <\?char text\?></p>}si;

	$Key=~s{<tr>(.*?)<\/tr>}{<\/colgroup><tbody valign=\"top\"><tr>$1<\/tr>}si;

	#$Key=~s{(<thead([^\>]+)\>(.*?)<\/thead>)}{&Key_Thead($1)}gesi;

	$Key=~s{<table\-wrap>}{<table-wrap position=\"background\">\n<caption><p><bold>Action: check your manuscript information</bold></p>\n<p>Please check that the information in the table is correct. We use this information in the online version of your article and for sharing with third party indexing sites, where applicable.</p></caption>}gsi;

	$Key=~s{<p><p>}{<p>}gsi;

	$Key=~s{<\/p>\n<break\/>}{\n<break\/>}gsi;
		
	#$Key=~s{(https\:\/\/search\.crossref.org\/funding)}{<uri xlink\:href=\"$1\">$1<\/uri>}si;
	
	return $Key;
}

sub Key_Thead
{
	my $Thead=shift;

	$Thead=~s{<td }{<th }gsi;
	$Thead=~s{<\/td>}{<\/th>}gsi;
	
	
	return $Thead;
}

sub OUP_Figxref
{
	my $Fig_Xref=shift;

	my @Fig=split(",",$Fig_Xref);

	my @F;
	foreach my $Value(@Fig)
	{
		push(@F,"<figxref>$Value<\/figxref>");
	}

	my $Final_Fig=join(",",@F);

	$Final_Fig=~s{<figxref> }{ <figxref>}gsi;

	$Final_Fig=~s{ <\/figxref>}{<\/figxref> }gsi;
	
	
	
	
	return $Final_Fig;
}

