sub OUP_Manuscript
{
	my $Manuscript=shift;

	if($Manuscript!~m{<CategoryCode>(ERRATUM|CORRIG)</CategoryCode>}gsi)
	{
		$Manuscript="";
	}
	
	return $Manuscript;
}

sub LWW_Orchid1
{
	my $Orchid=shift;
	my $Meta=shift;

	opendir DIR,$Source_Dir or die "can't read '$Source_Dir' $!\n";
	my @files = map{ "$_" }grep{ /(\.txt)$/i }readdir( DIR );
	closedir DIR;

	my @Cadmus;
	foreach my $Value(@files)
	{
		my $M;
		my $T_File=$Source_Dir."\\$Value";
	open (TXT, $T_File) || die "Can't open file '$T_File': $!\n";
	{ local $/; $_=<TXT>; $M=$_; }
	close(TXT);

	push(@Cadmus,$M);

	}

	my $Final_Cadmus=join("\n",@Cadmus);

	$Meta=$Meta."\n".$Final_Cadmus;
	$Meta=~s{\n}{}gsi;
	$Meta=~s{<contrib\-id contrib\-id\-type=\"orcid\"([^\>]*)\>(.*?)<\/contrib\-id>}{<xref ref\-type=\"orcid\" rid=\"orcid$2\">}gsi;

	my $Meta_Path=$ARGV[16];
		      
	open (XML, ">$Meta_Path") || die "Can't create XML file '$Meta_Path': $!\n";
	{
 
       
		print XML $Meta;
	}
	close(XML);

	#system("perl /home/pagemajik/Documents/PERL_PostscriptImage/XhtmlToXML_A1_PERL/UTF8.pl \"$Meta_Path\"");

	open (TXT, $Meta_Path) || die "Can't open file '$Meta_Path': $!\n";
	{ local $/; $_=<TXT>; $Meta=$_; }
	close(TXT);

	$Meta=~s{(\&\#x(.*?)\;)}{&Entity($1)}gesi;

	

	unlink($Meta_Path);
	
	my $Given_name;

	my $Given_name1;
	my $Given_name2;
	my $Given_name3;
	my $Given_name4;
	my $Surname;
	my $Surname1;
	my $Surname2;

	$Orchid=~s{<x>([^\<]+)\<\/x><\/name>}{<\/name><x>$1<\/x>}gsi;
	
	if($Orchid=~m{<given\-names>(.*?)<\/given\-names>}gsi)
	{
		$Given_name=$1;
		$Given_name1=$1;
		$Given_name2=$1;
		$Given_name3=$1;
		$Given_name4=$1;

	      
		
	}
	 $Given_name1=~s{^(\w)(.*)}{$1}si;

	 $Given_name2=~s{([A-Z])(\w+)}{$1}gs;
			     
	$Given_name=~s{\s$}{}si;
	$Given_name1=~s{\s$}{}si;
	$Given_name2=~s{\s$}{}si;
	$Given_name3=~s{\s$}{}si;
	$Given_name4=~s{\s$}{}si;

	$Given_name4=~s{(\w+) ([A-Z])$}{$1}s;
	

	if($Orchid=~m{<surname>(.*?)<\/surname>}gsi)
	{
		$Surname=$1;
		$Surname1=$1;
		$Surname2=$1;
		$Surname=~s{\s$}{}gsi;
		$Surname1=~s{\s$}{}gsi;
		$Surname2=~s{\s$}{}gsi;
		$Surname=~s{\[(\w+)\]}{}gsi;
		$Surname1=~s{\[(\w+)\]}{}gsi;
		$Surname2=~s{\[(\w+)\]}{}gsi;

		
		
	}

	$Surname1=~s{\-}{ }gsi;
	$Surname1=~s{\&rsquo\;}{\'}gsi;


	$Surname2=~s{\&([a-z])(\w+)\;}{$1}gsi;

	
	$Given_name3=~s{\&([a-z])(\w+)\;}{$1}gsi;

	$Given_name3=~s{\&([a-z])(\w+)\;}{$1}gsi;

	$Given_name3=~s{\&\#x(\w+)\;}{$1}gsi;

	
	

	$Meta=~s{\&([a-z])(\w+)\;}{$1}gsi;

	$Meta=~s{\&\#x(\w+)\;}{$1}gsi;

	

	my $Meta1=$Meta;

	
	
	while($Meta=~m{<contrib([^\>]*)\>(.*?)<\/contrib>}gsi)
	{
		my $Au=$2;

		my $Au3=$2;

		my $Au_Without=$2;

		my $Au_Without1=$2;

		$Au_Without=~s{<surname>([^\<]+)\<\/surname>}{$1}gsi;

		$Au_Without=~s{(\s?)<\/given\-names>}{<\/given\-names>}gsi;

		$Au_Without=~s{(\s?)<\/surname>}{<\/surname>}gsi;
		
		$Au_Without=~s{<given\-names>([^\<]+)\<\/given\-names>}{$1}gsi;

		$Au_Without=~s{<surname>([^\<]+)\<\/surname>}{$1}gsi;

		$Au_Without1=~s{<surname>([^\<]+)\<\/surname><given\-names>([^\<]+)\<\/given\-names>}{$2 $1}gsi;

		$Au_Without1=~s{<prefix>([^\<]+)\<\/prefix>}{}gsi;
			    
		$Au_Without1=~s{ {1,}}{ }gsi;

		
		
		
		if($Au=~m{<name><surname>$Surname(\s?)<\/surname><given\-names>$Given_name([\s\.]?)</given\-names>}si)
		{
			my $Au1=$Au;

			

				
			
			if($Au1=~m{<xref ref\-type=\"([^\"]+)\" rid=\"orcid([^\"]+)\"}si)
			{
				my $I=$2;

				

				

				if($Meta1=~m{<aff id=\"orcid$I\">(.*?)<\/aff>}gsi)
				{

				my $Id=$1;

				

				$Orchid=~s{<x>([^\<]+)\<\/x><\/contrib>}{<contrib-id contrib-id-type="orcid">https://orcid.org/$Id</contrib-id><x>$1<\/x><\/contrib>}gsi;

				$Orchid=~s{(<x>([^\<]+)\<\/x><xref ([^\>]+)\><xref ([^\>]+)\>)<\/contrib>}{<contrib-id contrib-id-type="orcid">https://orcid.org/$Id</contrib-id>$1<\/contribs>}gsi;
				
