				$Orchid=~s{</name></contrib>}{<\/name><contrib-id contrib-id-type="orcid">https://orcid.org/$Id</contrib-id><\/contrib>}si;

				push(@LWW_Orchid_Content,"<p content\-type=onlyforpdf\">ORCID iD for $Given_name $Surname: <uri xlink\:href=\"https://orcid.org/$Id\">$Id<\/uri></p>");
			}
			}
		}

		elsif($Au=~m{<name><surname>$Surname1(\s?)<\/surname><given\-names>$Given_name2([\s\.]?)</given\-names>}si)
		{
			
			my $Au1=$Au;
			if($Au1=~m{<xref ref\-type=\"([^\"]+)\" rid=\"orcid([^\"]+)\"}si)
			{
				my $I=$2;

				if($Meta1=~m{<aff id=\"orcid$I\">(.*?)<\/aff>}gsi)
				{

				my $Id=$1;

				

