sub LWW_Orchid
{
	my $Orchid=shift;
	my $Meta=shift;
	my $Journal_Name=shift;

	
	opendir DIR,$Source_Dir or die "can't read '$Source_Dir' $!\n";
	my @files = map{ "$_" }grep{ /(\.txt|legacy\.xml)$/i }readdir( DIR );
	closedir DIR;

	my @Cadmus;
	foreach my $Value(@files)
	{
		my $M;
		my $T_File=$Source_Dir."\\$Value";
	open (TXT, $T_File) || die "Can't open file '$T_File': $!\n";
	{ local $/; $_=<TXT>; $M=$_; }
	close(TXT);

	push(@Cadmus,$M);

	}

	my $Final_Cadmus=join("\n",@Cadmus);

	

	$Meta=$Meta."\n".$Final_Cadmus;

	$Meta=~s{ {1,}}{ }gsi;
	$Meta=~s{\n\s}{\n}gsi;
	
	$Meta=~s{\n}{}gsi;

	my $Jou=$Journal_Name;

	#if($Jou=~m{(MAT|STR|CIR)}gsi)
	#{

	$Meta=~s{https\:\/\/orcid\.org\/}{}gsi;
	$Meta=~s{<contrib\-id contrib\-id\-type=\"orcid\"([^\>]*)\>(\d+)\-(.*?)<\/contrib\-id>}{<xref ref\-type=\"orcid\" rid=\"$2\-$3\">}gsi;
	#}

	
	my $Meta_Path=$ARGV[16];
		      
	open (XML, ">$Meta_Path") || die "Can't create XML file '$Meta_Path': $!\n";
	{
 
       
		print XML $Meta;
	}
	close(XML);

	#system("perl /home/pagemajik/Documents/PERL_PostscriptImage/XhtmlToXML_A1_PERL/UTF8.pl \"$Meta_Path\"");

	open (TXT, $Meta_Path) || die "Can't open file '$Meta_Path': $!\n";
	{ local $/; $_=<TXT>; $Meta=$_; }
	close(TXT);

	#$Meta=~s{(\&\#x(.*?)\;)}{&Entity($1)}gesi;

	

	unlink($Meta_Path);
	
	my $Given_name;

	my $Given_name1;
	my $Given_name2;
	my $Given_name3;
	my $Given_name4;
	my $Surname;
	my $Surname1;
	my $Surname2;

	$Orchid=~s{<x>([^\<]+)\<\/x><\/name>}{<\/name><x>$1<\/x>}gsi;
	

	my $Orchid1=$Orchid;
	#$Orchid=~s{\-}{ }gsi;
	$Orchid=~s{<sc>(.*?)<\/sc>}{$1}gsi;

	my $Orchid3=$Orchid;
	
	
	if($Orchid3=~m{<given\-names>(.*?)<\/given\-names>}gsi)
	{
		
		$Given_name=$1;
		$Given_name1=$1;
		$Given_name2=$1;
		$Given_name3=$1;
		$Given_name4=$1;
		$Given_name=~s{<sc>(.*?)<\/sc>}{$1}gsi;
		$Given_name1=~s{<sc>(.*?)<\/sc>}{$1}gsi;
		$Given_name2=~s{<sc>(.*?)<\/sc>}{$1}gsi;
		$Given_name3=~s{<sc>(.*?)<\/sc>}{$1}gsi;
		$Given_name4=~s{<sc>(.*?)<\/sc>}{$1}gsi;
		$Given_name=~s{\[(\w+)\]}{}gsi;
