sub OUP_Multiple_Figure
{
	my $Figure=shift;
	my $Label=shift;

	if($Label=~m{(\d+)\&ndash;(\d+)}gsi)
	{
	my $startx=$1;
	my $endx=$2;
	my @Array_Id;

	$startx=$startx+1;

	for(my $i=$startx;$i<=$endx;$i++)
	{
		push(@Array_Id,"F$i");
	}

	my $Final_Id=join(" ",@Array_Id);

	$Figure=~s{<fig id=\"([^\"]+)\"}{<fig id=\"$1 $Final_Id\"}gsi;
	
	}

	$Figure=~s{<fig id=\"([^\"]+)\" position=\"float\" fig\-type=\"figure\"><label>(\w+)([\.\s\:]+)(\d+) and (\d+)}{<fig id=\"$1 F$5\" position=\"float\" fig\-type=\"figure\"><label>$2$3$4 and $5}gsi;

	

	
	
	return $Figure;
}

sub Figure_Xref
{
	my $Xref=shift;

	
	my $Figure_Tmp=shift;

	
	while($Figure_Tmp=~m{<fig id=\"F(\d+) ([^\"]+)\"}gsi)
	{
		my $F_Id="F$1";

		my $F_Id1="$2";

		$F_Id1=$F_Id1." ";

		

		if($F_Id1=~m{$Xref }si)
		{
			
			$Xref="$F_Id";
			
		}

		
	}

	return $Xref;
}

sub Fxref
{
	my $Fxref=shift;
	my $Tmp=shift;
	my $Fig_Tmp=shift;

if($Fxref=~m{<xref ref\-type=\"fig\" rid=\"([^\"]+)\">}si)
{
	my $Fig=$1;
	my $Fig1=$1;

	if($Fig=~m{^F(\d+)$}si)
	{
	
	if($Tmp!~m{<fig id=\"$Fig\"}si)
	{
		$Fxref=~s{<xref ref\-type=\"fig\" rid=\"$Fig\">}{"<xref ref\-type=\"fig\" rid=\"".&Figure_Xref($Fig,$Fig_Tmp)."\">"}esi;
	}
			
	}

	if($Fig1=~m{F(\d+) F(\d+)}gsi)
	{

		
		my @F_Split=split(" ",$Fig1);

		my @Fig_Id;
		
		foreach my $Value(@F_Split)
		{
			if($Tmp!~m{<fig id=\"$Value\"}si)
			{
			$Value=~s{^(.*)$}{&Figure_Xref($Value,$Fig_Tmp)}esi;
			}

			push(@Fig_Id,$Value);
		}

		

                my @unique_words = uniq @Fig_Id;

		my $Final_Fig=join(" ",@unique_words);

		$Fxref=~s{<xref ref\-type=\"fig\" rid=\"([^\"]+)\">}{<xref ref\-type=\"fig\" rid=\"$Final_Fig\">};

		
	}


}



return $Fxref;
}

