	$Title=~s{<\/bold><bold>}{}gsi;

	
	
	return $Title;
}

sub Bio_Author
{
	my $Author=shift;

	$Author=~s{<refauSurname>(.*?)<\/refauSurname>}{<surname>$1<\/surname>}gsi;



	$Author=~s{<refauGivenName>(.*?)<\/refauGivenName>}{<given-names>$1<\/given-names>}gsi;

