	$Author=~s{<fmauGivenName>(.*?)<\/fmauGivenName>}{<given-names>$1<\/given-names>}gsi;

	$Author=~s{<fmcorrSurname>(.*?)<\/fmcorrSurname>}{<surname>$1<\/surname>}gsi;
	

	$Author=~s{<fmcorrGivenName>(.*?)<\/fmcorrGivenName>}{<given-names>$1<\/given-names>}gsi;


	$Author=~s{<surname><bold>(.*?)<\/bold><\/surname>}{<surname>$1<\/surname>}gsi;

	$Author=~s{<given\-names><bold>(.*?)<\/bold><\/given\-names>}{<given\-names>$1<\/given\-names>}gsi;

	$Author=~s{<given\-names>}{<givenname>}gsi;

	$Author=~s{<\/given\-names>}{<\/givenname>}gsi;

	$Author=~s{<x>([^\<]+)\<\/x>}{$1}gsi;

	

	my $Author1=$Author;

	if($Author1!~m{<contrib}gsi)
	{
			
	$Author=~s{<(\w+)name>([^\<]+)\<\/(\w+)name>(\s?)(\,?)(\.?)(\,?)(\s?)<(\w+)name>([^\<]+)\<\/(\w+)name>(\s?)(\,?)(\.?)(\,?)(\s?)}{<contrib contrib-type="author" corresp="no"><name><$1name>$2<\/$3name><x>$4$5$6$7$8</x><$9name>$10<\/$11name><x>$12$13$14$15$16</x><\/name><\/contrib>}gsi;
	}
	$Author=~s{<givenname>}{<given\-names>}gsi;

	$Author=~s{<\/givenname>}{<\/given\-names>}gsi;

	$Author=~s{<prefix><italic>(.*?)</italic></prefix>(\s?)<contrib ([^\>]+)\><name>}{<contrib $3><name><prefix>$1<\/prefix><x>$2<\/x>}gsi;

	
	
	return $Author;
}

