sub Graphical_Abstract
{
	my $Graphical_Abstract=shift;

	$Graphical_Abstract=~s{(<title>(.*?)<\/title>)}{$1<p><\?citation ga1\?><fig id=\"ga1\" position=\"float\">\n<caption>}gsi;

	$Graphical_Abstract=~s{<p><inline\-graphic ([^\>]+)\><\/p>}{<\/caption><graphic $1><\/fig><\/p>}gsi;

