	$Graphical_Abstract=~s{<sec>(.*?)<\/sec>}{$1}gsi;

	

	$Graphical_Abstract=~s{<\/fig><\/p>\n*<object\-id pub\-id\-type=\"referenceid\">(.*?)<\/object\-id>\n*<object\-id pub\-id\-type=\"videoid\">(.*?)<\/object-id>\n*<\/abstract>}{<media content-type=\"brightcove\" mimetype=\"video\" xlink:href="https://players.brightcove.net/$1/default_default/index.html?videoId=$2\">\n<object-id pub-id-type=\"referenceid\">$1</object-id>\n<object-id pub-id-type=\"videoid\">$2<\/object-id>\n</media><\/fig><\/p><\/abstract>}gsi;
	
	return $Graphical_Abstract;
}

