sub SecLevel
{
        my $secCont=shift;
        $secCont=~s#\n+#\n#gsi;
        $secCont=~s#\n#<enter>#gsi;
        $secCont=~s#<#\n<#gsi;
        $secCont=~s#>#>\n#gsi;
        my @Array=split("\n",$secCont);

        my $num='1';
        for (my $i=0; $i<scalar(@Array); $i++)
        {
                if ($Array[$i]=~m#<sec #si)
                {
                    $Array[$i]=~s#<sec #<sec$num #si;
                    $num++;
                }
                if ($Array[$i]=~m#</sec>#si)
                {
                    $num--;
                    $Array[$i]=~s#</sec>#</sec$num>#si;
                }
        }

        $secCont=join("",@Array);
        $secCont=~s#<enter>#\n#gsi;
        return $secCont;
}


