my $Suppl=shift;
my $doi=shift;
my $Journal_Cats=shift;

my $OUP=$Jou;
if($OUP=~m{<ext\-link Journal=\"$Journal_Cats\" xlink:href=\"([^\"]+)\"\/>}si)
{
	my $Href=$1;

	
	
	my $DOI=lc($doi);
	
	#$DOI=~s{(.*?)\/(.*?)\/(.*?)}{$3}gsi;
	$Href=~s{doi\:}{doi\/$DOI}gsi;

	
	$Href=~s{\#\#\#\#\#\#}{$DOI}gsi;


	$Href=~s{doi\:}{doi\/$DOI}gsi;

	
	$Href=~s{\#\#\#\#\#\#}{$DOI}gsi;
	
	
	$Suppl=~s{(<italic>JXB</italic> online)}{<ext\-link xmlns:xlink="http://www.w3.org/1999/xlink" ext-link-type="supplement_link" xlink:href=\"$Href\">$1<\/ext-link>}gsi;

	


	
}
	
	return $Suppl;
}

sub Ref_X
{
	my $Reference=shift;

	$Reference=~s{<x>}{}gsi;

	$Reference=~s{<\/x>}{}gsi;
	
	return $Reference;
}

sub Lww_Back_Matter
{
	my $Sec=shift;
	my $Journal_Name=shift;


	
	
	
	$Sec=~s{<sec(\d+)\/>}{<sec$1>}gsi;

if($Sec=~m{<sec(\d+)>}gsi)
{
	my $Digit=$1;

	if($Digit eq 2)
	{
		$Sec=~s{(<sec$Digit>)}{<sec1><title\/>\n<sec$Digit>}si;
		$Sec=~s{<\/sec1>}{}si;
		
	}

	if($Digit eq 3)
	{
		$Sec=~s{(<sec$Digit>)}{<sec1><title\/>\n<sec2><title\/>\n<sec$Digit>}si;
		$Sec=~s{<\/sec2>}{}si;
		$Sec=~s{<\/sec1>}{}si;
		
		
	}
}


	if($Sec=~m{<sec(\d+)>}si)
	{
		$Sec=~s{<\/Lww_Back_Matter>}{<sec1><empty><\/Lww_Back_Matter>}gsi;
	}

my @body1;
my ($lvl1,$prevlvl1);
$lvl1 = $prevlvl1 = 0;
 
@body1 = split ('\n', $Sec);

foreach my $line (@body1)
{
	if($line =~ /<sec([0-9])>/)
	{
                $lvl1=ord($1);
		
                my $closetag = '';
                for(my $i=$prevlvl1;$i>=$lvl1;$i--)
                {
                        my $l = chr($i);
			
                        $closetag = $closetag . "\n</sec$l>";
			
                }
                $line = $closetag . "\n" . $line;
                $prevlvl1 = $lvl1;
        }
}

my $lines =join("\n",@body1);
$Sec=$lines;

	$Sec=~s{<sec(\d+)><empty>}{}gsi;

	$Sec=~s/<sec(\d+)>/'<sec id="s'.$sec++.'">'/segi;

	$Sec=~s{<\/sec(\d+)>}{<\/sec>}gsi;

	$Sec=~s{<sec id=\"([^\"]+)\">}{<sec id=\"$1\" sec\-type=\"Back_Matter\">}gsi;

	$Sec=~s{(<title>(.*?)<\/title>)}{&Remove_Track($1)}gesi;
	
	my $ANE_Journal_Name=$Journal_Name;

	
	if($ANE_Journal_Name eq "ANE")
	{
		
		$Sec=~s{(<title>(.*?)<\/title>)}{&Remove_Track($1)}gesi;

		

		$Sec=~s{<sec id=\"([^\"]+)\" sec\-type=\"Back_Matter\">(\n*)<title>(Ack)(.*?)<\/title>}{<sec id=\"$1\" sec\-type=\"$3$4\">\n<title>$3$4<\/title>}gsi;
	}
	

	my $Jats1=$Jats_Type;

	if($Jats1 eq "jats")
	{
		$Sec=~s{<p content\-type=\"([^\"]+)\">}{<p content\-type=\"Back_Matter_$1\">}gsi;
	}


	my $Journal_Name_Jats=$Journal_Name;

	if($Journal_Name_Jats=~m{(JW9)}gsi)
	{
		$Sec=~s{<sec id=\"([^\"]+)\" sec\-type=\"Back_Matter\"><title>(\w+)([^\<]*)\</title>}{<sec id=\"$1\" sec\-type=\"Back_Matter_$2\"><title>$2$3<\/title>}gsi;

		$Sec=~s{(s?)\">}{\">}gsi;


		
		my @Fn=("conflict","funding","study","author","patient","data","acknowledgment","supplementary");

my @Fn_Group;

my $F_Count="0001";

foreach my $Value(@Fn)
{
	my $Fn_Tmp=$Sec;
	while($Sec=~m{(<sec id=\"([^\"]+)\" sec\-type=\"Back_Matter_$Value\">(.*?)<\/sec>)}gsi)
	{
		my $Fn=$1;

		$Sec=~s{\Q$Fn\E}{}gsi;

		
		push(@Fn_Group,"$Fn");

		
	}
}

my $Final_Fn=join("\n",@Fn_Group);

$Sec=$Final_Fn."\n".$Sec;

$Sec=~s{ sec\-type=\"Back\_Matter\_(\w+)\"}{ sec\-type=\"Back\_Matter\"}gsi;


		
	}
	elsif($Journal_Name_Jats=~m{^(XCS)$}gsi)
	{
		$Sec=~s{<sec id=\"([^\"]+)\" sec\-type=\"Back_Matter\"><title>(\w+)([^\<]*)\</title>}{<sec id=\"$1\" sec\-type=\"Back_Matter_$2\"><title>$2$3<\/title>}gsi;

