sub Alternate_Names
{
	my $Names=shift;

	$Names=~s{(<name>(.*?)<\/name>)}{&Contrib_Author($1)}gesi;

	
	
	return $Names;
}

sub Contrib_Author
{
	my $Author=shift;

	

	$Author=~s{<x>([^\<]+)\<\/x><\/name>}{<\/name><x>$1<\/x>}gsi;
	
	my $Author1=$Author;
	my $Author2=$Author;
	my $Author3=$Author;
	my $Author4=$Author;
	my $Author5=$Author;

	

	if($Author1=~m{\[fmTransSurName\](.*?)\[\/fmTransSurName\]([\(\s\.]+)\[fmTransGivenName\](.*?)\[\/fmTransGivenName\]}si)
	{
		
