sub OUP_Bibxref
{
	my $Fig_Xref=shift;

	my @Fig=split(",",$Fig_Xref);

	my @F;
	foreach my $Value(@Fig)
	{
		push(@F,"<bibxref>$Value<\/bibxref>");
	}

	my $Final_Fig=join("<sup>,<\/sup>",@F);

	$Final_Fig=~s{<bibxref> }{ <bibxref>}gsi;

	$Final_Fig=~s{ <\/bibxref>}{<\/bibxref> }gsi;
	
	
	$Final_Fig=~s{<\/sup> }{ <\/sup>}gsi;
	
	return $Final_Fig;
}

sub OUP_Bibxref_online
{
	my $Fig_Xref=shift;

	my @Fig=split(",",$Fig_Xref);

	my @F;
	foreach my $Value(@Fig)
	{
		push(@F,"<onlinebibxref>$Value<\/onlinebibxref>");
	}

	my $Final_Fig=join(",",@F);

	$Final_Fig=~s{<onlinebibxref> }{ <onlinebibxref>}gsi;

	$Final_Fig=~s{ <\/onlinebibxref>}{<\/onlinebibxref> }gsi;
	
	
	
	
	return $Final_Fig;
}

sub Orcid_Contrib
{
	my $Orcid=shift;
	
	my $Tmp=shift;

	
	
	my $Orcid1=$Orcid;
	my $Orcid2=$Orcid;

	if($Orcid1!~m{<contrib\-id contrib\-id\-type=\"orcid\">}gsi)
	{
	if($Orcid2=~m{<OrcXref>(.*?)<\/OrcXref>}gsi)
	{
		my $Xref=$1;

		if($Tmp=~m{<FMOrcid><OrcXref>$Xref<\/OrcXref>(.*?)<\/FMOrcid>}gs)
		{
			my $Link=$1;

			$Orcid=~s{<contrib ([^\>]+)\>}{<contrib $1><contrib-id contrib-id-type="orcid">https://orcid.org/$Link</contrib-id>}gsi;

			$Orcid=~s{<OrcXref>(.*?)<\/OrcXref>}{}gsi;
		}
		
	}

	}
	else
	{
		$Orcid=~s{<OrcXref>(.*?)<\/OrcXref>}{}gsi;
	}
	

	$Orcid=~s{https\:\/\/orcid\.org\/https\:\/\/orcid\.org\/}{https\:\/\/orcid\.org\/}gsi;
	
	return $Orcid;
	
}


