sub Model
{
	my $Model=shift;

	
	
	$Model=~s{<url>(.*?)<\/url>}{<ext\-link ext\-link\-type=\"uri\" xlink\:href=\"$1\">$1<\/ext\-link>}gsi;

	my $Model_Uri=$1;

	if($Model_Uri=~m{https\:\/\/sketchfab\.com\/3d-models\/(.*?)$}gsi)
	{
		my $Link=$1;

		
		$Model=~s{<\/object\-id>}{$Link<\/object\-id>}gsi;
	}

	$Model=~s{<\/fig>}{"<graphic xlink\:href=\"$FileName\_MD000".$Model_Count++."\.eps\" content\-type=\"onlyforpdf\"\/><\/fig>"}gesi;

	$Model=~s{<graphic xlink\:href=\"$FileName\_MD000(\d\d).eps\" content\-type=\"onlyforpdf\"\/>}{<graphic xlink\:href=\"$FileName\_MD00$1.eps\" content\-type=\"onlyforpdf\"\/>}gsi;
	
	return $Model;
}

