		$Au_Without1=~s{<surname>([^\<]+)\<\/surname><given\-names>([^\<]+)\<\/given\-names>}{$2 $1}gsi;

		$Au_Without1=~s{<prefix>([^\<]+)\<\/prefix>}{}gsi;
			    
		$Au_Without1=~s{ {1,}}{ }gsi;


		$Au=~s{<other\-author\-middlename>(.*?)<\/other\-author\-middlename>}{}gsi;

		$Au=~s{\n{1,}}{\n}gsi;

		
		
		if($Au=~m{<other\-author\-firstname>$Given_name(\.?)</other\-author\-firstname><other\-author\-lastname>$Surname</other\-author\-lastname>}si)
		{
			my $Au1=$Au;

			my $Au2=$Au;

			
			

			if($Au2=~m{<email>(.*?)<\/email>}gsi)
			{
				$Email=$1;
			}
			
			
			
			if($Au1=~m{<person\-id type=\"orcid\">(.*?)<\/person\-id>}si)
			{
					

				my $Id=$1;

				


				$Orchid1=~s{<\/contrib>}{<contrib-id contrib-id-type="orcid">https://orcid.org/$Id</contrib-id><\/contrib>}gsi;
				

				

				push(@LWW_Orchid_Content,"ORCID iD for $Given_name $Surname: <uri xlink\:href=\"https://orcid.org/$Id\">$Id<\/uri>");
				
				
			}
		}
	}

	$Orchid1=~s{<\/contribs>}{<\/contrib>}gsi;

	
	$Orchid1=~s{<contrib ([^\>]+)\>(.*?)(<contrib\-id ([^\>]+)\>(.*?)<\/contrib\-id>)}{<contrib $1>$3$2}gsi;

	#$Orchid1=~s{<contrib\-id ([^\>]+)\>(.*?)<\/contrib\-id>}{<contrib\-id $1 content-type=\"$2\">$2<\/contrib\-id>}gsi;

	$Orchid1=~s{<contrib contrib\-type=\"author non\-byline\" corresp=\"([^\"]+)\"><contrib\-id contrib\-id\-type=\"orcid\" content\-type=\"([^\"]+)\">(.*?)</contrib\-id>}{<contrib contrib\-type=\"author non\-byline\" corresp=\"$1\">}gsi;

	
	

	#$Orchid1=~s{<contrib\-id ([^\>]+)\>}{<contrib\-id $1 authenticated=\"true\">}gsi;

	$Orchid1=~s{<contrib\-id ([^\>]+)\>([^\<]+)\<\/contrib\-id><\/contrib>}{<\/contrib>}gsi;

	$Orchid1=~s{<contrib\-id ([^\>]+)\>([^\<]+)\<\/contrib\-id><\/contrib>}{<\/contrib>}gsi;

	$Orchid1=~s{<contrib\-id ([^\>]+)\>([^\<]+)\<\/contrib\-id><\/contrib>}{<\/contrib>}gsi;

	$Orchid1=~s{<contrib\-id ([^\>]+)\>([^\<]+)\<\/contrib\-id><\/contrib>}{<\/contrib>}gsi;

	
	my $Orchid2=$Orchid1;

	if($Orchid2=~m{corresp=\"no\"}gsi)
	{
		$Orchid1=~s{<\/name>}{<\/name><email content-type=\"onlyforxml\">$Email<\/email>}gsi;
		$Orchid1=~s{(<email ([^\>]+)\>(.*?)<\/email>)(<x>([^\<]+)\<\/x><degrees>([^\<]+)\<\/degrees>)}{$4$1}gsi;
		$Orchid1=~s{<email content\-type=\"onlyforxml\"></email>}{}gsi;
	}


	my $Orchid3=$Orchid1;

	if($Orchid3=~m{<contrib contrib-type=\"author non-byline\"}gsi)
	{
		
		$Orchid1=~s{<email content-type=\"onlyforxml\">(.*?)</email>}{}gsi;
	}
	

	
	return $Orchid1;
}

