	if($Box=~m{<box(\d+)>}gsi)
	{
		
		$Box=~s{<\/Brill_back_matter>}{\n<box1><empty><\/Brill_back_matter>}gsi;
	}

	

my @body;
my ($lvl,$prevlvl);
$lvl = $prevlvl = 0;
 
@body = split ('\n', $Box);

foreach my $line (@body)
{
	if($line =~ /<box([0-9])>/)
	{
                $lvl=ord($1);
		
                my $closetag = '';
                for(my $i=$prevlvl;$i>=$lvl;$i--)
                {
                        my $l = chr($i);
                        $closetag = $closetag . "\n</box$l>";
			
                }
                $line = $closetag . "\n" . $line;
                $prevlvl = $lvl;
        }
}

my $lines =join("\n",@body);
$Box=$lines;

my $Sec="1";


$Box=~s{<box(\d+)><empty>}{}gsi;

$Box=~s/<box(\d+)>/'<sec id="ack1-'.$Sec++.'">'/segi;

$Box=~s{<\/box(\d+)>}{<\/sec>}gsi;

$Box=~s{<sec ([^\>]+)\><title(\d+)>}{<sec $1 sec\-type=\"heading-$2\"><title>}gsi;

$Box=~s{<Brill_back_matter>(.*?)<\/Brill_back_matter>}{$1}gsi;

$Box=~s{<BrillEMText>(.*?)<\/BrillEMText>}{<p><\?attributepistart content-type=\"flush left\"\?>$1<\/p>}gsi;

$Box=~s{<BrillEMTextInd>(.*?)<\/BrillEMTextInd>}{<p><\?attributepistart content-type=\"indent\"\?>$1<\/p>}gsi;



$Box=~s{<\/BrillSecA>}{}gsi;
$Box=~s{<\/BrillSecB>}{}gsi;
$Box=~s{<\/BrillSecC>}{}gsi;
$Box=~s{<\/BrillSecD>}{}gsi;

$Box=~s{<sec ([^\>]+)\>}{<ack id=\"ack1\">}si;



$Box=~s{<\/sec>}{}si;

$Box=~s{<\/ack>}{}si;

$Box=$Box."<\/ack>";



return $Box;
}

