		if($Contribution_Tmp=~m{<sec ([^\>]+)\>\n*<title>Author Contribution(s?)</title>(.*?)<\/sec>}gsi)
		{
		my $Contrib_Sec=$3;

		if($Contrib_Sec=~m{$N1 \((.*?)\)}gsi)
		{
			my @R=split(",",$1);

			
