				$Value=~s{Resources}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/contributor-roles/resources\" degree-contribution=\"equal\">$Value</role>}gsi;

