				$Value=~s{Writing \&ndash; original draft}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing\-original\-draft\" degree-contribution=\"equal\">$Value</role>}gsi;
				$Value=~s{Writing\&\#x2014;original draft}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing\-original\-draft\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing\-original draft}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing\-original\-draft\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing \- original draft}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing\-original\-draft\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing \&ndash; review \&amp; editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing \&\#x2013; review \&\#x0026; editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing\&\#x2014;review \&amp; editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing\-review \&\#x0026; editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

			                 	
				$Value=~s{Writing \- review \&\#x0026; editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing \- review \&amp; editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{Writing\&\#x2014;review and editing}{<role vocab=\"credit\" vocab\-identifier=\"http://credit.niso.org\" vocab-term=\"$Value\" vocab-term-identifier=\"http://credit.niso.org/writing-review-editing\" degree-contribution=\"equal\">$Value</role>}gsi;

				$Value=~s{\[equal\]}{}gsi;
				$Value=~s{\[lead\]}{}gsi;
				$Value=~s{\[supporting\]}{}gsi;

				if($Value11=~m{\[lead\]}gsi)
				{
					$Value=~s{degree-contribution=\"equal\">}{degree-contribution=\"lead\">}gsi;
				}
				elsif($Value11=~m{\[supporting\]}gsi)
				{
					$Value=~s{degree-contribution=\"equal\">}{degree-contribution=\"supporting\">}gsi;
				}
				
				push(@Role_List,$Value);

				
			}

			my $Final_Role=join("",@Role_List);

