sub Alt_Figure
{
	my $Figure=shift;

	my $Fig=$Figure;

	my @Alt;
	while($Fig=~m{(<alt\-text>(.*?)<\/alt\-text>)}gsi)
	{
		push(@Alt,$1);
	}

	my $Final_Alt=join("\n",@Alt);

	if($Final_Alt ne "")
	{
		$Figure=~s{<alt\-text>(.*?)<\/alt\-text>}{}gsi;
		$Figure=~s{<graphic xlink\:href=\"([^\"]+)\"\/>}{<graphic xlink\:href=\"$1\">$Final_Alt<\/graphic>}gsi;
	}
	
	return $Figure;
}

sub LWW_Related_Query
{
	my $Query=shift;

	my $Query1=$Query;

	my $Query2=$Query;

	my $Source_Dir=$ARGV[0];

	$Source_Dir=~s{\\Word(.*)}{\\Artwork\\print}si;

	$Source_Dir=~s{\\Editorial(.*)}{\\Artwork\\print}si;

	$Source_Dir=~s{\\Jaws_Conversion(.*)}{\\Artwork\\print}si;

	

	while($Query1=~m{<graphic xlink\:href=\"([^\"]+)\"}gsi)
		{

			
			my $Figure_Name=$1;

			my $Final_Figure_Name;
			

			$Figure_Name=~s{\.(\w+)$}{}gsi;

			if(-e "$Source_Dir\\$Figure_Name.eps")
			{
				$Final_Figure_Name="$Source_Dir\\$Figure_Name.eps";
			}
			elsif(-e "$Source_Dir\\$Figure_Name.jpg")
			{
				$Final_Figure_Name="$Source_Dir\\$Figure_Name.jpg";
			}

			elsif(-e "$Source_Dir\\$Figure_Name.gif")
			{
				$Final_Figure_Name="$Source_Dir\\$Figure_Name.gif";
			}

			elsif(-e "$Source_Dir\\$Figure_Name.tif")
			{
				$Final_Figure_Name="$Source_Dir\\$Figure_Name.tif";
			}
			elsif(-e "$Source_Dir\\$Figure_Name.tiff")
			{
				$Final_Figure_Name="$Source_Dir\\$Figure_Name.tiff";
			}
			elsif(-e "$Source_Dir\\$Figure_Name.png")
			{
				$Final_Figure_Name="$Source_Dir\\$Figure_Name.png";
			}
			
			

			my $image_file = $Final_Figure_Name;


my $exif_tool = new Image::ExifTool;

$exif_tool->ExtractInfo($Final_Figure_Name);

my $title = $exif_tool->GetValue('Description') ||    # Description tag
            $exif_tool->GetValue('ImageDescription') || # ImageDescription tag
	    $exif_tool->GetValue('Subject'); # ImageDescription tag	




my $Label;

if($Query2=~m{<fig id=\"F(\d+)\"}gsi)
{
	$Label=$1;

	$Label=~s{<([^\>]+)\>}{}gsi;
}



if($title=~m{query}gsi)
{

	my $AHA_Journals=$Journal_Cats;

if($AHA_Journals=~m{(HAE|STR|HCV|HCQ|HCG|HHF|HCI|HYP|RES|ATV|CIR)}gsi)
{
	$Query=~s{<caption><p>}{<caption><p><\!\-\-\[AU: Figure $Label is low resolution and could result in poor-quality graphics in the final publication. Please send higher-resolution versions of these figures, or approval to proceed with the figures as shown in your proof. Further information on figure specifications is available at https://www.ahajournals.org/figure-guidelines.\]-->}gsi;
}
else
{
	$Query=~s{<caption><p>}{<caption><p><\!\-\-\[AU: Figure $Label is low quality (blurred/unsharp text). Please provide print quality images with minimum 300 dpi resolution, in any of the following formats: TIFF, EPS, MS Word, MS PowerPoint, MS Excel, AI - Adobe Illustrator 10.0, PSD - Adobe PhotoShop 7.0, JPEG, Acrobat PDF.\]-->}gsi;
}

# Clean up the ExifTool object
undef $exif_tool;


}		
	
	return $Query;
	
	
}
}
sub Name_Space
{
	my $Name=shift;

	my $Name1=$Name;

	if($Name1=~m{<given\-names>(.*?)<\/given\-names>}gsi)
	{
		my $Given_Names=$1;

		if($Given_Names!~m{<\?pistart xml\:space=\" \"\?>}gsi)
		{
			$Name=~s{<\/given\-names>}{<\?pistart xml\:space=\" \"\?><\/given\-names>}gsi;
		}
	}
	
	return $Name;
}

sub Caption_Query
{
	my $Contrib=shift;

	my @Query;

	while($Contrib=~m{(<\!\-\-(.*?)\-\->)}gsi)
	{
		push(@Query,$1);
	}

	my $Final_Query=join("",@Query);

	$Contrib=~s{<\!\-\-(.*?)\-\->}{}gsi;

	$Contrib=~s{<caption><p>}{<caption><p>$Final_Query}si;
	
	return $Contrib;
	
}

