sub Plos_Contrib
{
	my $Contrib=shift;

	my $Contrib1=$Contrib;

	my @Af;
	while($Contrib1=~m{(<aff ([^\>]+)\>(.*?)<\/aff>)}gsi)
	{
		

		push(@Af,$1);
	}

	my $Final_Aff=join("\n",@Af);

	$Contrib=~s{<aff ([^\>]+)\>(.*?)<\/aff>}{}gsi;

	$Contrib=~s{<\/contrib\-group>}{<\/contrib\-group>\n$Final_Aff}gsi;

	
	
	return $Contrib;
}

sub Contrib_PLOS_Role
{
	my $Contrib=shift;

	my $Contrib1=$Contrib;

	if($Contrib1=~m{<role>}gsi)
	{
		$Contrib=~s{<\/name>(.*?)<role>(.*?)<\/role>\n*<\/contrib>}{<\/name><role>$2<\/role>$1<\/contrib>}gsi;

		$Contrib=~s{<aff>}{<aff id=\"edit1\">}gsi;

		

		$Contrib=~s{<\?pistart xml\:space=\"\, \"\?></institution>}{\, </institution>}gsi;

		

		$Contrib=~s{<\/role>}{<\/role><xref ref-type=\"aff\" rid=\"edit1\"\/>}gsi;

		
	}

	return $Contrib;
}

sub PLOS_Affiliation
{
	my $Aff=shift;

	$Aff=~s{<institution>(.*?)<\/institution>}{$1}gsi;
	$Aff=~s{<country>(.*?)<\/country>}{$1}gsi;
	$Aff=~s{<addr-line>(.*?)<\/addr-line>}{$1}gsi;

	$Aff=~s{<aff([^\>]*)\><label>(.*?)<\/label>(.*?)<\/aff>}{<aff1$1><label>$2<\/label><addr\-line>$3<\/addr\-line><\/aff1>}gsi;

	$Aff=~s{<aff([^\>]*)\>(.*?)<\/aff>}{<aff$1><addr\-line>$2<\/addr\-line><\/aff>}gsi;

	$Aff=~s{<aff1}{<aff}gsi;

	$Aff=~s{<\/aff1}{<\/aff}gsi;
	
	return $Aff;
}

sub PLOS_Reference_Citation
{
my $Reference=shift;



$Reference=~s{<xref ([^\>]+)\>(\d+)\&\#x2013;(\d+)<\/xref>}{<xref rid=\"CIT000$2\" ref-type=\"bibr\">$2<\/xref>\&\#x2013;<xref rid=\"CIT000$3\" ref-type=\"bibr\">$3<\/xref>}gsi;

$Reference=~s{\"CIT000(\d\d)\"}{\"CIT00$1\"}gsi;

$Reference=~s{\"CIT00(\d\d\d)\"}{\"CIT0$1\"}gsi;

$Reference=~s{\"CIT000(\d\d\d)\"}{\"CIT0$1\"}gsi;

return $Reference;
}

sub Plos_Figure_Label
{

	my $Figure=shift;

	$Figure=~s{\.(\s?)<\/label>}{<\?pistart xml\:space=\"\.\"?><\/label>}gsi;

	$Figure=~s{<\/label>\.(\s?)}{<\?pistart xml\:space=\"\.\"?><\/label>}gsi;

	$Figure=~s{\.(\s?)(<\?ext\-link xlink\:href=\"([^\"]+)\"\?>)<\/label>}{<\?pistart xml\:space=\"\.\"?>$2<\/label>}gsi;

	
	
	return $Figure;
}

sub Plos_Equal_Contrib
{
	my $Contrib=shift;

	my $Contrib1=$Contrib;

	my $Contrib2=$Contrib;

	if($Contrib1=~m{<xref ref\-type=\"fn\" rid=\"([^\"]+)\"><sup>\&\#x262F\;</sup></xref>}gsi)
	{
		$Contrib=~s{<contrib contrib-type=\"author\" xlink:type=\"simple\">}{<contrib contrib-type=\"author\" equal-contrib=\"yes\" xlink\:type=\"simple\">}gsi;
	}

	if($Contrib2=~m{<xref ref\-type=\"fn\" rid=\"([^\"]+)\">\&\#x262F\;</xref>}gsi)
	{
		$Contrib=~s{<contrib contrib-type=\"author\" xlink:type=\"simple\">}{<contrib contrib-type=\"author\" equal-contrib=\"yes\" xlink\:type=\"simple\">}gsi;
	}

	$Contrib=~s{<xref ref\-type=\"fn\" rid=\"([^\"]+)\"><sup>\&\#x2021\;</sup></xref>}{<xref ref-type=\"fn\" rid=\"econtrib001\"><sup>\&\#x2021\;</sup></xref>}gsi;

	
	
	return $Contrib;
}

