		my $Latex_File2="$Artwork_Path1";

		$Latex_File1=~s{\.tex}{\.pdf}gsi;

		$Latex_File2=~s{\.tex}{\.bsl}gsi;
		
		$Art_File_Name2=~s{\.eps}{\.bsl}gsi;

		my $K=$Art_File_Name1;
		$Art_File_Name2=~s{\.pdf}{\.bsl}gsi;
		$K=~s{\.pdf}{\.bsl}gsi;
		
		my $K1=$Art_File_Name1;
		$K1=~s{\.pdf}{\.tex}gsi;
		
		
		if(-e "$Latex_File")
		{
		
		open(ENT,$Latex_File) || die "Can't open file '$Latex_File': $!\n";	
		{ local $/; $_=<ENT>; $Tex=$_; }
		close(ENT);

		}

		if($Tex=~m{\\\[(.*?)\\\]}gsi)
		{
			my $D=$1;

			$D=~s{\n}{}gsi;
			
			$Disp=~s{<graphic ([^\>]+)\>}{<graphic $1><\?TEX $D \?><\?Eqn$F $Art_File_Name1\?><\/alternatives>}gsi;
			$Disp=~s{\.eps}{\.pdf}gsi;

			

			

		copy("$Latex_File1","$Artwork_Path\\Online\\$Art_File_Name1");

		copy("$Latex_File2","$Artwork_Path\\Online\\$K");

		copy("$Artwork_Path1","$Artwork_Path\\Online\\$K1");
		
		}
		elsif($Tex=~m{\\\((.*?)\\\)}gsi)
		{
			my $D=$1;

			$D=~s{\n}{}gsi;

			
			
			$Disp=~s{<graphic ([^\>]+)\>}{<graphic $1><\?TEX $D \?><\?Eqn$F $Art_File_Name1\?><\/alternatives>}gsi;
			$Disp=~s{\.eps}{\.pdf}gsi;

			

		copy("$Latex_File1","$Artwork_Path\\Online\\$Art_File_Name1");

		copy("$Latex_File2","$Artwork_Path\\Online\\$K");

		copy("$Artwork_Path1","$Artwork_Path\\Online\\$K1");
		
		}
		elsif($Tex=~m{\\begin\{document\}(.*?)\\end\{document\}}gsi)
		{
			my $D=$1;

			$D=~s{\n}{}gsi;
			
			$Disp=~s{<graphic ([^\>]+)\>}{<graphic $1><\?TEX $D \?><\?Eqn$F $Art_File_Name1\?><\/alternatives>}gsi;
			$Disp=~s{\.eps}{\.pdf}gsi;

		copy("$Latex_File1","$Artwork_Path\\Online\\$Art_File_Name1");

		copy("$Latex_File2","$Artwork_Path\\Online\\$K");

		copy("$Artwork_Path1","$Artwork_Path\\Online\\$K1");
		
		}
		
		else
		{
			$Disp=~s{<graphic ([^\>]+)\>}{<graphic $1><\?Eqn$F $Art_File_Name1\?><\/alternatives>}gsi;
			$Disp=~s{\.eps}{\.pdf}gsi;
		
		}
	}

	else
	{
		
			$Disp=~s{<graphic ([^\>]+)\>}{<graphic $1><\?Eqn$F $Art_File_Name1\?><\/alternatives>}gsi;
			$Disp=~s{\.eps}{\.pdf}gsi;
		
	}
	
	}

	
	return $Disp;
}

