	$Reference=~s{(<ext\-link ext\-link\-type=\"uri\" xlink\:href=\"https\:\/\/doi\.org([^\>]+)\>(.*?)<\/ext\-link>)}{<comment>$1<\/comment>}gsi;

	$Reference=~s{(<ext\-link ext\-link\-type=\"uri\" xlink\:href=\"http\:\/\/doi\.org([^\>]+)\">(.*?)<\/ext\-link>)}{<comment>$1<\/comment>}gsi;
	
	return $Reference;
}

