sub Sub_Article
{
	my $Article=shift;

	$Article=~s{\.r(\d+)\"}{\.r$Sub_Count\"}gsi;

	$Article=~s{\.r(\d+)</article\-id>}{\.r$Sub_Count</article-id>}gsi;

	$Article=~s{rel\-obj(\d+)}{rel\-obj$Sub_Count}gsi;

	
	
	$Sub_Count++;
	
	return $Article;
}


sub Sub_Article1
{
