sub Plos_Reference_Styling
{
	my $Ref=shift;

	my $Ref1=shift;


	
	
		$Ref1=~s{<surname>(.*?)<\/surname>}{<refauSurname>$1<\/refauSurname>}gsi;

		$Ref1=~s{<forename>(.*?)<\/forename>}{ <refauGivenName>$1<\/refauGivenName>}gsi;

		$Ref1=~s{<articletitle>(.*?)<\/articletitle>}{\. <reftitleArticle>$1<\/reftitleArticle>}gsi;

		$Ref1=~s{<journaltitle>(.*?)<\/journaltitle>}{ <reftitleJournal>$1<\/reftitleJournal>}gsi;

		$Ref1=~s{<year>(.*?)<\/year>}{\. <refpubdateYear>$1<\/refpubdateYear>}gsi;

		$Ref1=~s{<volume>(.*?)<\/volume>}{;<refvolumeNumber>$1<\/refvolumeNumber>}gsi;

		$Ref1=~s{<issue>(.*?)<\/issue>}{\(<refissueNumber>$1<\/refissueNumber>\)}gsi;

		$Ref1=~s{<fpage>(.*?)<\/fpage>}{\:<refpageFirst>$1<\/refpageFirst>}gsi;

		$Ref1=~s{<lpage>(.*?)<\/lpage>}{\&\#x2013;<refpageLast>$1<\/refpageLast>}gsi;

		$Ref1=~s{(<doi>(.*?)<\/doi>)}{&Plos_Ref_Doi($1)}gesi;

		$Ref1=~s{<doi>(.*?)<\/doi>}{\. <refUrl>$1<\/refUrl>}gsi;

		$Ref1=~s{<\/refauGivenName><refauSurname>}{<\/refauGivenName>\, <refauSurname>}gsi;

		

		$Ref=$Ref1;
		
		

	
	return $Ref;
}

