	my $Entry=shift;

	my $Entry1=$Entry;

	if($Entry1=~m{style=\"background\:\&num;(\w+)\;}gsi)
	{

		my $Color=$1;

		
		$Entry=~s{<oasis\:entry([^\>]+)\>(.*?)<\/oasis\:entry>}{<oasis\:entry$1><\?scolor\_start $Color\?>$2<\?scolor_end\?><\/oasis\:entry>}gsi;

		$Entry=~s{<\?scolor\_start ([^\>]+)\><table([^\>]+)\>}{<table$2><\?scolor\_start $1\>}gsi;
		
	$Entry=~s{<\?scolor_start FFFFFF\?>(.*?)<\?scolor_end\?>}{$1}gsi;
	
		
		
	}
	
	return $Entry;
}

sub Citation_ID
{
	my $Citation=shift;
	my $Tmp=shift;

	$Citation=~s{\?}{}gsi;
	my @Cit=split(" ",$Citation);

	my @C;

	foreach my $Value(@Cit)
	{
		if($Tmp!~m{<\?Citation $Value\?>}gsi)
		{
	
		push(@C,"<\?Citation $Value\?>");
		}
	
	
	}

	my $Final_Citation=join("",@C);
	
	return $Final_Citation;
}


sub Xref_Citation
{
	my $Citation=shift;
	my $Type=shift;

	$Citation=~s{\?}{}gsi;
	my @Cit=split(" ",$Citation);

	my @C;

	foreach my $Value(@Cit)
	{
		
	
		push(@C,"<xrefduplicate><xref ref\-type=\"$Type\" rid=\"$Value\"><\/xref><\/xrefduplicate>");
		
	
	
	}

	my $Final_Citation=join("",@C);
	
	return $Final_Citation;
}

