sub lineno
{
	my ($pre) = @_;
	my $lno = $pre =~ s/\n/\n/gs;
	$pre =~ /\n$/ ? $pre = "" :  $pre =~ s/^.+?\n([^\n]+)$/$1/gs;
	my $linesp=$lno+1;
	my $colsp=length($pre)+1; #=length($pre)+1;
	if(length($linesp)<=6)
	{
		$linesp=substr("",0,6-length($linesp)).$linesp;
	}
	if(length($colsp)<=6)
	{
		$colsp=substr("",0,6-length($colsp)).$colsp;
	}
	return "Line No [".$linesp.":".$colsp."]   ";
}

sub rgb_to_hex {
    my ($r, $g, $b) = @_;
    return sprintf("#%02X%02X%02X", $r, $g, $b);
}


